let serial; // WebSerial instance
let distance = 0; // Distance data from Arduino

function setup() {
  createCanvas(400, 400);

  // Initialize WebSerial
  serial = new p5.WebSerial();
  serial.open(); // Open serial connection

  // Event handlers
  serial.on("connected", () => console.log("Connected to WebSerial"));
  serial.on("data", serialEvent); // Callback when data is received
  serial.on("error", serialError); // Callback for errors

  // Request user to select port
  textSize(16);
  textAlign(CENTER, CENTER);
  text("Select a serial port to connect to Arduino", width / 2, height / 2);
}

function draw() {
  background(200);

  // Display the received distance
  fill(0);
  textSize(24);
  textAlign(CENTER, CENTER);
  text(`Distance: ${distance.toFixed(2)} cm`, width / 2, height / 2);
}

// Function to handle serial data
function serialEvent() {
  let data = serial.readLine(); // Read a line of data from serial
  if (data) {
    distance = float(data); // Convert to float
    console.log(`Received Distance: ${distance}`); // Debugging
  }
}

// Function to handle serial errors
function serialError(err) {
  console.error(`Serial Error: ${err}`);
}

