  // 显示初始消息
  console.log("Waiting for distance data...");
}

function draw() {
  background(220);

  // 在画布上显示距离数据
  textSize(16);
  fill(0);
  text(`Distance: ${distance} cm`, 20, 30);
}

// 初始化 Web Serial
function allSerialStuff() {
  if (!navigator.serial) {
    alert("WebSerial is not supported in this browser. Try Chrome or MS Edge.");
  }

  // 检查可用串口
  serial.getPorts();
  serial.on("noport", makePortButton);   // 如果没有可用串口，创建选择按钮
  serial.on("portavailable", openPort); // 如果串口可用，打开它
  serial.on("requesterror", portError); // 错误处理
  serial.on("data", serialEvent);       // 当接收到数据时调用
  serial.on("close", makePortButton);   // 如果串口关闭，显示选择按钮

  // 添加串口连接和断开事件监听器
  navigator.serial.addEventListener("connect", portConnect);
  navigator.serial.addEventListener("disconnect", portDisconnect);
}

// 创建串口选择按钮
function makePortButton() {
  portButton = createButton("Choose Port");
  portButton.position(10, 10);
  portButton.mousePressed(choosePort);
}

// 打开串口选择窗口
function choosePort() {
  if (portButton) portButton.show();
  serial.requestPort();
}

// 打开串口并初始化通信
function openPort() {
  serial.open().then(() => {
    console.log("Serial port opened.");
    if (portButton) portButton.hide(); // 隐藏按钮
  });
}

// 当接收到串口数据时触发
function serialEvent() {
  let data = serial.readLine(); // 从串口读取一行数据
  if (data) {
    distance = data.trim(); // 去掉多余的空格或换行符
    console.log("Received distance:", distance); // 将距离数据打印到控制台
  }
}

// 处理串口错误
function portError(err) {
  console.error("Serial port error:", err);
}

// 处理串口连接事件
function portConnect() {
  console.log("Serial port connected.");
  serial.getPorts(); // 刷新可用串口
}

// 处理串口断开事件
function portDisconnect() {
  console.log("Serial port disconnected.");
  serial.close();
}

