// ref: https://thecodingtrain.com/tracks/ml5js-beginners-guide/ml5/hand-pose

let handpose;
let video;
let hands = [];
let particles = [];
let particleScale, theme, graphics;
let flippedVideo;

let bgm;
let leftHandSounds = [];
let rightHandSounds = [];

let fingerStates = {
  "Left": { 4: false, 8: false, 12: false, 16: false, 20: false },
  "Right": { 4: false, 8: false, 12: false, 16: false, 20: false },
};

let yuan = [];

let starryColors = [
  "#F9FF76",
  "#F5BA42",
  "#A0D3FF",
  "#FFF17C",
  "#FFE082",
];

function preload() {
  bgm = loadSound("音乐盒.mp3");

  leftHandSounds.push(loadSound("琴音 1.mp3"));
  leftHandSounds.push(loadSound("琴音 2.mp3"));
  leftHandSounds.push(loadSound("琴音 3.mp3"));
  leftHandSounds.push(loadSound("琴音 4.mp3"));
  leftHandSounds.push(loadSound("琴音 5.mp3"));
  leftHandSounds.push(loadSound("琴音 6.mp3"));
  leftHandSounds.push(loadSound("琴音 7.mp3"));
  leftHandSounds.push(loadSound("琴音 8.mp3"));
  leftHandSounds.push(loadSound("钢舌鼓.mp3"));
  leftHandSounds.push(loadSound("钢舌鼓2.mp3"));
  leftHandSounds.push(loadSound("钢舌鼓3.mp3"));

  rightHandSounds.push(loadSound("钢舌鼓4.mp3"));
  rightHandSounds.push(loadSound("钢舌鼓5.mp3"));
  rightHandSounds.push(loadSound("钢舌鼓6.mp3"));
  rightHandSounds.push(loadSound("琴音 3.mp3"));
  rightHandSounds.push(loadSound("琴音 5.mp3"));
  rightHandSounds.push(loadSound("琴音 8.mp3"));
}

function setup() {
  createCanvas(800, 600);

  video = createCapture(VIDEO);
  video.size(640, 480);
  video.hide();

  flippedVideo = ml5.flipImage(video);
  handpose = ml5.handpose(video, modelReady);

  handpose.on("predict", gotHands);

  createParticles();

  if (bgm && bgm.isLoaded()) {
    bgm.loop();
    bgm.amp(0.2);
  }
}

function modelReady() {
  console.log("Handpose model ready!");
}

function gotHands(results) {
  hands = results;
}

function draw() {
  background(0);

  // 显示视频
  push();
  translate(width, 0);
  scale(-1, 1);
  image(video, 0, 0, width, height);
  pop();

  for (const p of particles) p.update();
  for (const p of particles) p.draw();
  image(graphics, 0, 0);

  assignHands();
  waterPaint();

  // 在小窗口显示手势
  let smallW = video.width * 0.3;
  let smallH = video.height * 0.3;
  push();
  let offsetX = width - smallW - 30;
  let offsetY = 30;
  translate(offsetX + smallW, offsetY);
  scale(-1, 1);
  image(video, 0, 0, smallW, smallH);

  hands.forEach((hand) => {
    hand.landmarks.forEach(([x, y]) => {
      let mappedX = map(x, 0, video.width, 0, smallW);
      let mappedY = map(y, 0, video.height, 0, smallH);
      fill(0, 255, 0);
      noStroke();
      ellipse(mappedX, mappedY, 5);
    });

    const skeletonPairs = [
      [0, 1], [1, 2], [2, 3], [3, 4],
      [0, 5], [5, 6], [6, 7], [7, 8],
      [0, 9], [9, 10], [10, 11], [11, 12],
      [0, 13], [13, 14], [14, 15], [15, 16],
      [0, 17], [17, 18], [18, 19], [19, 20],
    ];

    stroke(0, 255, 0);
    skeletonPairs.forEach(([start, end]) => {
      let sx = map(hand.landmarks[start][0], 0, video.width, 0, smallW);
      let sy = map(hand.landmarks[start][1], 0, video.height, 0, smallH);
      let ex = map(hand.landmarks[end][0], 0, video.width, 0, smallW);
      let ey = map(hand.landmarks[end][1], 0, video.height, 0, smallH);
      line(sx, sy, ex, ey);
    });
  });
  pop();

  // 绘制波纹
  drawRipples();
}

function assignHands() {
  if (hands.length === 1) {
    let h = hands[0];
    h.handedness = guessHandedness(h);
  } else if (hands.length === 2) {
    let h0_x = averageX(hands[0]);
    let h1_x = averageX(hands[1]);
    if (h0_x < h1_x) {
      hands[0].handedness = "Left";
      hands[1].handedness = "Right";
    } else {
      hands[0].handedness = "Right";
      hands[1].handedness = "Left";
    }
  }
}

function guessHandedness(hand) {
  let thumb = hand.landmarks[4];
  let indexTip = hand.landmarks[8];
  if (thumb[0] < indexTip[0]) {
    return "Left";
  } else {
    return "Right";
  }
}

function waterPaint() {
  const fingerTipToKnuckleMap = {
    4: 3,
    8: 6,
    12: 10,
    16: 14,
    20: 18,
  };
  let threshold = 20;

  hands.forEach((hand) => {
    let handedness = hand.handedness || "Left";
    Object.keys(fingerTipToKnuckleMap).forEach((fIndexStr) => {
      let fIndex = parseInt(fIndexStr);
      let kIndex = fingerTipToKnuckleMap[fIndex];
      let fingertip = hand.landmarks[fIndex];
      let knuckle = hand.landmarks[kIndex];
      let distance = dist(fingertip[0], fingertip[1], knuckle[0], knuckle[1]);
      let isPressed = distance < threshold;

      if (!fingerStates[handedness][fIndex] && isPressed) {
        playRandomNote(handedness);
        const x = width - fingertip[0];
        const y = fingertip[1];
        addParticle(x, y);

        // 当手指按下时，加入一个初始波纹数据
        yuan.push([x, y, 0]);
      }
      fingerStates[handedness][fIndex] = isPressed;
    });
  });
}

function playRandomNote(handedness) {
  let sound;
  if (handedness === "Left") {
    sound = random(leftHandSounds);
  } else {
    sound = random(rightHandSounds);
  }

  if (sound && sound.isLoaded()) {
    sound.stop();
    let randRate = random(0.8, 1.2);
    let randPan = random(-0.5, 0.5);
    sound.rate(randRate);
    sound.pan(randPan);
    sound.amp(1);
    sound.play();
  }
}

function drawRipples() {
  for (let p of yuan) {
    let alphaVal = 255 - p[2] * 2;
    if (alphaVal < 0) alphaVal = 0;

    noFill();

    strokeWeight(0.8);
    let c1 = color(random(starryColors));
    c1.setAlpha(alphaVal);
    stroke(c1);
    circle(p[0], p[1], p[2] * 1.5);

    strokeWeight(1.45);
    let c2 = color(random(starryColors));
    c2.setAlpha(alphaVal);
    stroke(c2);
    circle(p[0], p[1], p[2] * 0.8);

    strokeWeight(2);
    let c3 = color(random(starryColors));
    c3.setAlpha(alphaVal);
    stroke(c3);
    circle(p[0], p[1], p[2] * 0.6);

    p[2]++;
  }

  yuan = yuan.filter((p) => p[2] < 100);
}

class Particle {
  constructor(x, y) {
    this.pos = createVector(
      x || random(-50, width + 50),
      y || random(-50, height + 50)
    );
    this.color = random(theme.colors);
    this.r = random(0.5, 2);
    this.life = random(50, 150);
  }

  update() {
    const dir =
      noise(this.pos.x / particleScale, this.pos.y / particleScale) *
      TWO_PI *
      particleScale;
    this.pos.add(createVector(cos(dir) / 2, sin(dir) / 2));
    this.life -= 1;

    if (
      this.pos.x < -50 ||
      this.pos.x > width + 50 ||
      this.pos.y < -50 ||
      this.pos.y > height + 50 ||
      this.life <= 0
    ) {
      this.pos.set(random(-50, width + 50), random(-50, height + 50));
      this.life = random(50, 150);
    }
  }

  draw() {
    graphics.fill(this.color);
    graphics.circle(this.pos.x, this.pos.y, this.r);
  }
}

function createParticles() {
  particleScale = random(800, 2000);
  theme = random([
    {
      colors: [
        "#FFFFFF",
        "#cfe4f4",
        "#c79b12",
        "#72b9f0",
        "#1265c7",
        "#eeedb6",
        "#2d5a8f",
        "#625cd4",
      ],
      background: "#150832",
    },
  ]);

  for (let i = 0; i < 200; i++) particles.push(new Particle());

  graphics = createGraphics(width, height);
  graphics.background(theme.background);
  graphics.noStroke();
}

function addParticle(x, y) {
  particles.push(new Particle(x, y));
  if (particles.length > 300) particles.shift();
}

