let handpose;
let video;
let hands = [];
let particles = [];
let particleScale, theme, graphics;

// 音频和播放控制
let bgm; // 背景音乐
let songs = [];
let i = 0;
let ra, pa;
let smoothRa = 1.0; // 平滑速率
let smoothPa = 0.0; // 平滑声道
let lastPlayedTime = 0; // 上次播放时间
const playInterval = 500; // 播放间隔

function preload() {
  // 加载音频
  bgm = loadSound(
    "bgmmm.mp3",
    () => console.log("Background music loaded"),
    (err) => console.error("Error loading bgmmm.mp3", err)
  );
  songs[0] = loadSound(
    "d3.mp3",
    () => console.log("d3.mp3 loaded"),
    (err) => console.error("Error loading d3.mp3", err)
  );
}

function setup() {
  createCanvas(800, 600);

  // 创建视频捕捉
  video = createCapture(VIDEO);
  video.size(640, 480);
  video.hide();

 flippedVideo = ml5.flipImage(video);
  handpose = ml5.handpose(video, modelReady);

  // 当检测到手势时，回调处理
  handpose.on("predict", gotHands);

  // 创建粒子效果
  createParticles();

  // 播放背景音乐
  if (bgm && bgm.isLoaded()) {
    bgm.loop();
    bgm.amp(0.2); // 设置背景音乐音量
  }
}

function modelReady() {
  console.log("Handpose model ready!");
}

function gotHands(results) {
  // 保存检测到的手势
  hands = results;
}

function draw() {
  background(0);
  push();
  translate(width, 0); // 水平翻转
  scale(-1, 1);
  image(video, 0, 0, width, height);
  pop();

  // 绘制粒子效果
  for (const p of particles) p.update();
  for (const p of particles) p.draw();
  image(graphics, 0, 0);

  // 手势处理和音频控制
  waterPaint();
}

function waterPaint() {
  hands.forEach((hand, handIndex) => {
    // 遍历每只手
    hand.landmarks.forEach((keypoint, keypointIndex) => {
      // 绘制关键点
      fill("#ffffff");
      noStroke();
      circle(keypoint[0], keypoint[1], 10);

      // 检测食指尖（索引 8）
      if (keypointIndex === 8) {
        const x = width - keypoint[0]; // 翻转后的手势坐标
        const y = keypoint[1];

        console.log(Hand ${handIndex}, Index finger detected at:, x, y);

        // 播放音频
        ra = map(x, 0, width, 0.8, 1.2);
        pa = map(y, 0, height, -1, 1);

        // 平滑参数
        smoothRa = lerp(smoothRa, ra, 0.1);
        smoothPa = lerp(smoothPa, pa, 0.1);

        // 控制音频播放
        if (
          songs[0] &&
          songs[0].isLoaded() &&
          !songs[0].isPlaying() &&
          millis() - lastPlayedTime > playInterval
        ) {
          console.log("Playing sound with rate:", smoothRa, "pan:", smoothPa);
          songs[0].rate(smoothRa);
