function draw() {
  background(0);

  push();
  translate(width, 0);
  scale(-1, 1);
  image(video, 0, 0, width, height);
  pop();

  image(graphics, 0, 0);
  for (const p of particles) p.update();
  for (const p of particles) p.draw();

  hands.forEach((hand) => {
    hand.landmarks.forEach((landmark) => {
      const x = width - landmark.x * width; 
      const y = landmark.y * height;

      fill(192, 157, 56);
      noStroke();
      ellipse(x, y, 10);
    });

    const skeletonPairs = [
      [0, 1], [1, 2], [2, 3], [3, 4],
      [0, 5], [5, 6], [6, 7], [7, 8],
      [0, 9], [9, 10], [10, 11], [11, 12],
      [0, 13], [13, 14], [14, 15], [15, 16],
      [0, 17], [17, 18], [18, 19], [19, 20],
    ];

    stroke(255, 255, 255);
    strokeWeight(2);
    skeletonPairs.forEach(([start, end]) => {
      const sx = width - hand.landmarks[start].x * width; // 修正水平翻转
      const sy = hand.landmarks[start].y * height;
      const ex = width - hand.landmarks[end].x * width; // 修正水平翻转
      const ey = hand.landmarks[end].y * height;
      line(sx, sy, ex, ey);
    });
  });

  // 水彩效果
  waterPaint();

  // 绘制波纹
  drawRipples();
}

function waterPaint() {
  const fingerTipToKnuckleMap = {
    4: 3,
    8: 6,
    12: 10,
    16: 14,
    20: 18,
  };
  let threshold = 0.05; // 相对距离阈值

  hands.forEach((hand) => {
    const handedness = hand.handedness;
    Object.keys(fingerTipToKnuckleMap).forEach((fIndexStr) => {
      const fIndex = parseInt(fIndexStr);
      const kIndex = fingerTipToKnuckleMap[fIndex];
      const fingertip = hand.landmarks[fIndex];
      const knuckle = hand.landmarks[kIndex];

      const distance = dist(
        fingertip.x, fingertip.y,
        knuckle.x, knuckle.y
      );

      if (!fingerStates[handedness][fIndex] && distance < threshold) {
        playRandomNote(handedness);

        const x = width - fingertip.x * width; // 修正水平翻转
        const y = fingertip.y * height;
        addParticle(x, y);
        yuan.push([x, y, 0]);
      }
      fingerStates[handedness][fIndex] = distance < threshold;
    });
  });
}

function playRandomNote(handedness) {
  let sound;
  if (handedness === "Left") {
    sound = random(leftHandSounds);
  } else {
    sound = random(rightHandSounds);
  }

  if (sound && sound.isLoaded()) {
    sound.stop();
    let randRate = random(0.8, 1.2);
    let randPan = random(-0.5, 0.5);
    sound.rate(randRate);
    sound.pan(randPan);
    sound.amp(1);
    sound.play();
  }
}

function drawRipples() {
  yuan.forEach((p) => {
    let alphaVal = 255 - p[2] * 2;
    if (alphaVal < 0) alphaVal = 0;

    noFill();

    strokeWeight(0.8);
    let c1 = color(random(starryColors));
    c1.setAlpha(alphaVal);
    stroke(c1);
    circle(p[0], p[1], p[2] * 1.5);

    p[2]++;
  });

  yuan = yuan.filter((p) => p[2] < 100);
}

