let seed = 100;
let colors = [];
let angle_c = 0;
let branch = 200;
let mySize = 200;
let t = 0;
let rez = 0;

let colorScheme = [
  { colors: ['#FF5252', '#FF4081', '#E040FB', '#7C4DFF'] },
  { colors: ['#40C4FF', '#18FFFF', '#64FFDA', '#69F0AE'] },
  { colors: ['#B2FF59', '#EEFF41', '#FFFF00', '#FFD740'] }
];
let bgcolor = ['#111', '#222', '#333'];

function setup() {
  seed = Math.random() * 999999;
  mySize = min(windowWidth, windowHeight) / 2;
  createCanvas(windowWidth, windowHeight, WEBGL);
}

function draw() {
  randomSeed(seed);
  let scheme = random(colorScheme);
  colors = scheme.colors;
  background(random(bgcolor));

  // 基础旋转和平移
  translate(0, 0, -mySize);
  rotateZ(HALF_PI);
  rotateX(sin(frameCount / 100) * 0.1);
  rotateY(sin(frameCount / 100) * 0.1);
  rotateZ(angle_c + frameCount / 150);

  // 两圈环状结构
  for (let i = 0; i < 2; i++) {
    circleForm(0, 0, mySize * 0.95 * (i + 1) / 2);
  }
  angle_c += TAU / 360 / 100;

  // 立方体分支
  push();
    let cubeSize = mySize / 1.5;
    let step = cubeSize;
    for (let i = -cubeSize/2; i < cubeSize + step; i += step) {
      for (let j = -cubeSize; j < cubeSize + step; j += step) {
        for (let k = -cubeSize; k < cubeSize + step; k += step) {
          push();
            translate(i, j, k);
            rotateX(frameCount / 200);
            rotateY(frameCount / 200);
            rotateZ(frameCount / 250);
            drawFuzzyPolygon(i, j, k);
          pop();
        }
      }
    }
  pop();

  t += 0.01;
  rez += 0.005;
}

// 在 3D 空间为线段 p→q 添加“毛茸茸”分支
function drawFuzzy3D(p, q, density, minLen, maxLen, col) {
  let dir = p5.Vector.sub(q, p);
  let mid = p5.Vector.add(p, q).mult(0.5);
  // 构造两个与 dir 垂直的单位向量
  let perp1 = createVector(-dir.y, dir.x, 0);
  if (perp1.mag() < 0.1) perp1 = createVector(0, -dir.z, dir.y);
  perp1.normalize();
  let perp2 = dir.copy().cross(perp1).normalize();

  stroke(col);
  for (let i = 0; i < density; i++) {
    let len = random(minLen, maxLen);
    let ang = random(TWO_PI);
    let offset = p5.Vector
      .add(perp1.copy().mult(cos(ang) * len),
           perp2.copy().mult(sin(ang) * len));
    strokeWeight(random(0.5, 1.5));
    line(mid.x, mid.y, mid.z,
         mid.x + offset.x,
         mid.y + offset.y,
         mid.z + offset.z);
  }
}

// 画“毛茸茸”多边形
function drawFuzzyPolygon(i, j, k) {
  let planeSize = mySize / random([16, 8, 4]);
  // 收集顶点
  let verts = [];
  for (let a = 0; a < TWO_PI; a += TWO_PI/20) {
    let x = planeSize * cos(a);
    let y = planeSize * sin(a);
    let z = planeSize * cos(a*2);
    verts.push(createVector(x, y, z));
  }
  // 按边绘制主线和毛茸茸
  for (let idx = 0; idx < verts.length; idx++) {
    let p = verts[idx];
    let q = verts[(idx+1)%verts.length];
    stroke(random(colors));
    strokeWeight(1);
    line(p.x, p.y, p.z, q.x, q.y, q.z);
    drawFuzzy3D(p, q, 8, 4, 12, color(255, 200));
  }
}

// 画“毛茸茸”环状分支
function circleForm(x, y, d) {
  // 预先计算一圈的基础角度
  let angStep = TAU / branch;
  // 为每一段生成并绘制
  for (let i = 0; i < branch; i++) {
    let rio = noise(i*0.1, frameCount*0.01) * 2;
    let ang1 = i * angStep + sin(frameCount*0.01 + i);
    let ang2 = ang1 + angStep * random(0.5, 1.5);
    let dd = d * map(cos(frameCount*0.01 + i), -1, 1, 0.1, 1);

    // 先采样出这一段上的若干点
    let pts = [];
    for (let a = ang1; a < ang2; a += 0.1/4) {
      let x1 = dd * cos(i);
      let y1 = dd * sin(a);
      let z1 = dd * rio * cos(a);
      // 两组：放大与原始，营造“粗细”变化
      pts.push(createVector(x1 * rio, y1 * rio, z1 * rio));
      pts.push(createVector(x1, y1, z1));
    }
    // 画线并加 fuzz
    for (let k = 0; k < pts.length - 1; k++) {
      let p = pts[k], q = pts[k+1];
      stroke(random(colors));
      strokeWeight(noise(i, frameCount*0.1));
      line(p.x, p.y, p.z, q.x, q.y, q.z);
      drawFuzzy3D(p, q, 8, 5, 15, color(255, 180));
    }
  }
}

// 辅助：生成一个振荡范围 [s,e] 的值
function iteration(s, e) {
  let tt = random(1, 100);
  let vv = random(0.01, 0.1);
  return map(cos(tt + frameCount * vv), -1, 1, s, e);
}

