let myVid, bodyPose, pose;
let p5lm;
let startTime;
let myPos = { x: 0, y: 0 };
let smoothPos = { x: 0, y: 0 };
let friends = {};

function setup() {
  createCanvas(640, 480);
  colorMode(HSB, 360, 100, 100, 100);
  noStroke();

  myVid = createCapture(VIDEO, { flipped: true });
  myVid.hide();

  bodyPose = ml5.bodyPose();
  bodyPose.detectStart(myVid, gotPoses);

  p5lm = new p5LiveMedia(this, "DATA", null, "slime-time-room");
  p5lm.on("data", gotData);

  startTime = millis();
}

function gotPoses(poses) {
  if (poses.length > 0) {
    let nose = poses[0].keypoints.find(k => k.part === "nose");
    if (nose) {
      myPos.x = width - nose.position.x;
      myPos.y = nose.position.y;
    }
  }
}

function draw() {
  background(0, 0, 10, 20);

  // 🕒 计算停留时间 -> 色相/饱和度变化
  let elapsed = millis() - startTime;
  let timeRatio = constrain(elapsed / (3 * 60 * 1000), 0, 1); // 3分钟渐变
  let myColor = color(340, map(timeRatio, 0, 1, 20, 80), 100); // 淡粉到深红

  smoothPos.x = lerp(smoothPos.x, myPos.x, 0.2);
  smoothPos.y = lerp(smoothPos.y, myPos.y, 0.2);

  // ✉️ 发送自己位置和颜色
  let data = { pos: smoothPos, h: hue(myColor), s: saturation(myColor) };
  p5lm.send(JSON.stringify(data));

  // 🫧 绘制自己
  drawBlob(smoothPos.x, smoothPos.y, 70, myColor);

  // 🫶 绘制朋友
  for (let id in friends) {
    let f = friends[id];
    let fColor = color(f.h, f.s, 100);
    drawBlob(f.pos.x, f.pos.y, 70, fColor);

    // 融合判定
    let d = dist(smoothPos.x, smoothPos.y, f.pos.x, f.pos.y);
    if (d < 140) {
      let mixCol = lerpColor(myColor, fColor, 0.5);
      let size = map(d, 0, 140, 130, 0);
      drawBlob((smoothPos.x + f.pos.x) / 2, (smoothPos.y + f.pos.y) / 2, size, mixCol, true);
    }
  }
}

function drawBlob(x, y, r, c, glow = false) {
  push();
  drawingContext.shadowBlur = glow ? 60 : 30;
  drawingContext.shadowColor = c;
  fill(c);
  ellipse(x, y, r, r);
  pop();
}

function gotData(data, id) {
  let d = JSON.parse(data);
  friends[id] = {
    pos: { x: d.pos.x, y: d.pos.y },
    h: d.h,
    s: d.s
  };
}

