// 风吹动的草地效果
// 基于SamuelYAN的代码简化版

// 变量声明
let canvasSize;
let grassBlades = []; // 存储草叶对象
let windForce = 0; // 风力大小
let windDirection = 0; // 风向
let grassColors = []; // 草的颜色

// 设置函数
function setup() {
  // 创建适合窗口大小的正方形画布
  canvasSize = min(windowWidth, windowHeight) * 0.9;
  createCanvas(canvasSize, canvasSize);

  // 设置草地颜色 - 几种绿色色调
  grassColors = [
    color(82, 149, 75), // 深绿色
    color(127, 191, 63), // 中绿色
    color(173, 212, 95), // 浅绿色
    color(53, 89, 51),   // 暗绿色
    color(200, 230, 160) // 非常浅的绿色
  ];

  // 创建草叶
  createGrass();

  // 设置帧率
  frameRate(30);
}

// 创建草叶函数
function createGrass() {
  // 清空草叶数组
  grassBlades = [];

  // 草的密度 - 决定有多少根草
  const grassDensity = 280;

  for (let i = 0; i < grassDensity; i++) {
    // 只在画布底部60%的区域生成草
    let xPos = random(width);
    let yPos = random(height * 0.4, height);

    // 创建草叶对象
    let blade = {
      x: xPos,
      y: yPos,
      height: random(20, 60), // 草的高度
      width: random(1, 3),    // 草的宽度
      bendFactor: random(0.1, 0.3), // 弯曲程度
      swaySpeed: random(0.01, 0.05), // 摇摆速度
      color: random(grassColors), // 随机选择一种绿色
      phase: random(TWO_PI)  // 不同的起始相位，使草叶摇摆不同步
    };

    grassBlades.push(blade);
  }
}

// 绘制函数
function draw() {
  // 设置天空颜色 (浅蓝色)
  background(135, 206, 235);

  // 更新风力 (使用噪声函数产生平滑变化)
  windForce = map(noise(frameCount * 0.01), 0, 1, 0.5, 2); 
  windDirection = map(noise(frameCount * 0.005 + 1000), 0, 1, -0.5, 0.5);

  // 绘制地面
  fill(139, 69, 19); // 棕色
  rect(0, height * 0.95, width, height * 0.05);

  // 按照y坐标排序草叶，这样前面的草叶会遮挡后面的草叶
  grassBlades.sort((a, b) => a.y - b.y);

  // 绘制每一根草
  for (let blade of grassBlades) {
    drawGrassBlade(blade);
  }
}

// 绘制单根草叶
function drawGrassBlade(blade) {
  push(); // 保存当前的变换状态

  // 移动到草叶的根部位置
  translate(blade.x, blade.y);

  // 计算弯曲程度 (受风力和风向影响)
  let bendAmount = sin(frameCount * blade.swaySpeed + blade.phase) * windForce * blade.bendFactor;
  bendAmount += windDirection;

  // 设置草叶颜色，增加一点透明度制造深度感
  let grassColor = color(blade.color);
  grassColor.setAlpha(230);
  stroke(grassColor);
  strokeWeight(blade.width);

  // 使用贝塞尔曲线绘制弯曲的草叶
  noFill();
  beginShape();
  // 草叶的根部
  vertex(0, 0);
  // 草叶的中间向侧面弯曲
  let controlX = blade.height * 0.3 * bendAmount;
  let controlY = -blade.height * 0.5;
  let endX = blade.height * 0.5 * bendAmount;
  let endY = -blade.height;
  // 使用贝塞尔曲线创造弯曲效果
  bezierVertex(controlX, controlY, endX, controlY, endX, endY);
  endShape();

  pop(); // 恢复之前的变换状态
}

// 当窗口大小改变时调整画布
function windowResized() {
  canvasSize = min(windowWidth, windowHeight) * 0.9;
  resizeCanvas(canvasSize, canvasSize);
  createGrass(); // 重新创建草叶以适应新的画布大小
}

// 鼠标点击时改变风向
function mousePressed() {
  // 从鼠标位置出发的风
  let mouseXNormalized = map(mouseX, 0, width, -2, 2);
  windDirection = mouseXNormalized;
}

