// 创建纹理效果
function createTexture() {
  textureGraphics.blendMode(MULTIPLY);

  // 创建噪声纹理
  for (let x = 0; x < width; x += 2) {
    for (let y = 0; y < height; y += 2) {
      let noiseVal = noise(x * 0.01, y * 0.01, 11.5);
      let alpha = map(noiseVal, 0, 1, 5, 20);
      textureGraphics.noStroke();
      textureGraphics.fill(10, 5, 0, alpha);
      textureGraphics.rect(x, y, 2, 2);
    }
  }

  // 添加一些随机线条增强纹理感
  textureGraphics.stroke(20, 10, 0, 8);
  textureGraphics.strokeWeight(0.5);
  for (let i = 0; i < 100; i++) {
    let x1 = random(width);
    let y1 = random(height);
    let x2 = x1 + random(-50, 50);
    let y2 = y1 + random(-50, 50);
    textureGraphics.line(x1, y1, x2, y2);
  }
}

