      y: random(height * 0.5, height * 0.95),
      width: random(width * 0.1, width * 0.5),
      height: random(height * 0.05, height * 0.3),
      density: random(0.6, 1.2),
      color: color(random(greenTones))
    };
    grassFields.push(field);
  }
}

// 创建单个草叶
function createGrassBlade() {
  // 选择一个草地区域
  let field = random(grassFields);

  // 在草地区域内随机位置
  let x = random(field.x - field.width/2, field.x + field.width/2);
  let y = random(field.y - field.height/2, field.y + field.height/2);

  // 创建草叶对象
  let blade = {
    x: x,
    y: y,
    field: field,
    length: random(10, 40) * field.density,  // 草的长度
    width: random(0.5, 2),  // 草的宽度
    angle: random(-0.3, 0.3),  // 初始角度偏移
    baseColor: color(random(greenTones)),  // 基础颜色
    tipColor: color(random(greenTones)),  // 尖端颜色
    swayFactor: random(0.3, 1.0),  // 摇摆幅度
    swaySpeed: random(0.5, 2.0),  // 摇摆速度
    phase: random(TWO_PI),  // 摇摆相位
    segments: floor(random(2, 6)),  // 草叶分段数
    originalX: x,  // 记录原始位置用于恢复
    originalY: y
  };

  // 添加到草叶数组
  grassBlades.push(blade);
}

function draw() {
  // 更新风向和强度，使用噪声产生平滑变化
  windDirection = map(noise(t * 0.1), 0, 1, -1, 1);
  windStrength = map(noise(t * 0.05 + 500), 0, 1, 0.3, 1.2);

  // 更新时间变量
  t += 0.05;

  // 清空字段图形缓冲区
  fieldGraphics.clear();

  // 绘制天空
  drawSky();

  // 绘制地面
  drawGround();

  // 更新和绘制每一根草
  drawGrass();

  // 绘制叠加效果
  drawOverlay();

  // 将所有图层绘制到主画布
  background(random(colors1));
  image(fieldGraphics, 0, 0);
  blendMode(MULTIPLY);
  image(textureGraphics, 0, 0);
  blendMode(BLEND);

  // 绘制边框
  drawBorder();

  // 更新鼠标影响
  updateMouseInfluence();
}

// 绘制天空
function drawSky() {
  // 渐变天空背景
  for (let y = 0; y < height * 0.6; y++) {
    let inter = map(y, 0, height * 0.6, 0, 1);
    let skyColor = lerpColor(color(random(skyTones)), color(random(skyTones)), inter);
    fieldGraphics.strokeWeight(1);
    fieldGraphics.stroke(skyColor);
    fieldGraphics.line(0, y, width, y);
  }

  // 添加一些扰动云纹理
  fieldGraphics.noStroke();
  for (let i = 0; i < 500; i++) {
    let x = random(width);
    let y = random(height * 0.5);
    let size = random(2, 10);
    let cloudColor = color(255, 255, 255, random(5, 20));
    fieldGraphics.fill(cloudColor);
    fieldGraphics.ellipse(x, y, size, size);
  }
}

// 绘制地面
function drawGround() {
  // 渐变地面
  for (let y = height * 0.6; y < height; y++) {
    let inter = map(y, height * 0.6, height, 0, 1);
    let groundColor = lerpColor(color(random(earthTones)), color(random(earthTones)), inter);
    fieldGraphics.strokeWeight(1);
    fieldGraphics.stroke(groundColor);
    fieldGraphics.line(0, y, width, y);
  }
}

// 绘制草
function drawGrass() {
  // 按y坐标排序草叶，这样远处的草在后面绘制
  grassBlades.sort((a, b) => a.y - b.y);

  for (let blade of grassBlades) {
    // 检查是否受到鼠标影响
    let influencedByMouse = false;
    let totalInfluence = {x: 0, y: 0};

    for (let influence of mouseInfluence) {
      let d = dist(blade.x, blade.y, influence.x, influence.y);
      if (d < influence.radius) {
        influencedByMouse = true;
        // 计算影响方向和强度
        let angle = atan2(blade.y - influence.y, blade.x - influence.x);
        let strength = map(d, 0, influence.radius, influence.strength, 0);
        totalInfluence.x += cos(angle) * strength;
        totalInfluence.y += sin(angle) * strength;
      }
    }

    // 更新草叶位置（如果受鼠标影响）
    if (influencedByMouse) {
      blade.x += totalInfluence.x;
      blade.y += totalInfluence.y;

      // 缓慢恢复到原始位置
      blade.x = lerp(blade.x, blade.originalX, 0.05);
      blade.y = lerp(blade.y, blade.originalY, 0.05);
    }

    // 计算风的影响角度
    let windAngle = blade.angle + sin(t * blade.swaySpeed + blade.phase) * windStrength * blade.swayFactor * windDirection;

    // 绘制草叶
    fieldGraphics.push();
    fieldGraphics.translate(blade.x, blade.y);

    // 使用设计师的线条样式效果
    fieldGraphics.drawingContext.setLineDash([2, 1, 0.5, 1.5]);
    fieldGraphics.strokeCap(ROUND);

    // 根据分段绘制草叶，形成优美的曲线
    for (let i = 0; i < blade.segments; i++) {
      let segmentLength = blade.length / blade.segments;
      let segmentAngle = windAngle * (i / blade.segments) * 2;

      // 颜色从底部到顶部渐变
      let segmentColor = lerpColor(blade.baseColor, blade.tipColor, i / blade.segments);
      segmentColor.setAlpha(200 - i * 20); // 顶部略透明

      fieldGraphics.stroke(segmentColor);
      fieldGraphics.strokeWeight(blade.width * (blade.segments - i) / blade.segments);

      fieldGraphics.line(0, 0, 
                         sin(segmentAngle) * segmentLength, 
                         -cos(segmentAngle) * segmentLength);

      fieldGraphics.translate(sin(segmentAngle) * segmentLength, 
                             -cos(segmentAngle) * segmentLength);
    }

    fieldGraphics.pop();
  }
}

// 绘制叠加效果
function drawOverlay() {
  overlayGraphics.clear();

  // 绘制一些光线效果
  overlayGraphics.blendMode(SCREEN);
  for (let i = 0; i < 20; i++) {
    let x = random(width);
    let ray = {
      x: x,
      width: random(10, 50),
      alpha: random(5, 20)
    };

    overlayGraphics.noStroke();
    overlayGraphics.fill(255, 255, 200, ray.alpha);
    overlayGraphics.rect(ray.x, 0, ray.width, height * 0.7);
  }

  // 将叠加效果应用到主字段
  fieldGraphics.blendMode(SCREEN);
  fieldGraphics.image(overlayGraphics, 0, 0);
  fieldGraphics.blendMode(BLEND);
}

// 绘制边框
function drawBorder() {
  noFill();
  stroke("#202020");
  strokeWeight(margin);
  rect(0, 0, width, height);
}

// 鼠标拖动时更新影响点
function mouseDragged() {
  // 更新最旧的影响点
  let oldestIndex = frameCount % mouseInfluence.length;
  mouseInfluence[oldestIndex] = {
    x: mouseX,
    y: mouseY,
    strength: 2,
    radius: 100
  };
  return false; // 防止默认行为
}

// 鼠标点击时添加新的影响点
function mousePressed() {
  // 添加一个强影响点
  let oldestIndex = frameCount % mouseInfluence.length;
  mouseInfluence[oldestIndex] = {
    x: mouseX,
    y: mouseY,
    strength: 5,
    radius: 150
  };
  return false; // 防止默认行为
}

// 更新鼠标影响点
function updateMouseInfluence() {
  for (let i = 0; i < mouseInfluence.length; i++) {
    // 减少强度
    mouseInfluence[i].strength *= 0.9;
    mouseInfluence[i].radius *= 0.95;
  }
}

// 当窗口调整大小时重设画布
function windowResized() {
  mySize = min(windowWidth, windowHeight) * 0.9;
  margin = mySize / 100;
  resizeCanvas(mySize, mySize);

  // 重新创建图形缓冲区
  fieldGraphics = createGraphics(width, height);
  overlayGraphics = createGraphics(width, height);
  textureGraphics = createGraphics(width, height);

  // 重新初始化
  createTexture();
  initializeGrassFields();

  // 重置草叶
  grassBlades = [];
  for (let i = 0; i < grassCount; i++) {
    createGrassBlade();
  }
}

