let particles = [];
let yuan = [];
let scale, theme, graphics, themeWidth;

let bgm;
let songs = [];
let song, ra, pa;
let i = 0;

let prevPointer = [
  [
    { x: 0, y: 0 },
    { x: 0, y: 0 },
    { x: 0, y: 0 },
    { x: 0, y: 0 },
  ],
  [
    { x: 0, y: 0 },
    { x: 0, y: 0 },
    { x: 0, y: 0 },
    { x: 0, y: 0 },
  ],
];

let fingertips = [8, 12, 16, 20];

function setup() {
  createCanvas(640, 480);
  createParticles();

  bgm.loop();
  bgm.amp(0.5);

  handsfree = new Handsfree({
    hands: {
      enabled: true,
      maxNumHands: 2,
      minDetectionConfidence: 0.4,
      minTrackingConfidence: 0.5,
    },
  });
  handsfree.start();

  // Ensure webcam video is hidden
  let videoElements = document.querySelectorAll("video");
  videoElements.forEach((video) => (video.style.display = "none"));
}

function preload() {
  songs[0] = loadSound("d3.mp3");
  bgm = loadSound("bgmmm.mp3");
}

function draw() {
  background(0);

  i++;
  i = i % 50;

  for (const p of particles) p.update();
  for (const p of particles) p.draw();
  image(graphics, 0, 0);

  waterPaint();
}

function waterPaint() {
  const hands = handsfree.data?.hands;

  if (hands?.pinchState) {
    hands.pinchState.forEach((hand, handIndex) => {
      hand.forEach((state, finger) => {
        if (hands.landmarks?.[handIndex]?.[fingertips[finger]]) {
          let x =
            width -
            hands.landmarks[handIndex][fingertips[finger]].x * width;
          let y =
            hands.landmarks[handIndex][fingertips[finger]].y * height;

          if (state === "start") {
            prevPointer[handIndex][finger] = { x, y };
            yuan.push([x, y, i]);

            // Trigger sound and visual effects
            ra = map(x, 0.1, height, 0.5, 1.3);
            pa = map(x, 0.1, width, -1, 1);
            song = songs[0];
            song.rate(ra);
            song.pan(pa);
            song.amp(1);
            song.play();
          }

          prevPointer[handIndex][finger] = { x, y };
        }
      });
    });
  }

  yuan.forEach((p) => {
    noFill();
    strokeWeight(0.8);
    stroke(255, 255 - p[2] * 1.87);
    circle(p[0], p[1], p[2] * 1.25, p[2] * 1.25);

    strokeWeight(1.45);
    stroke(255, 255 - p[2] * 1.65);
    circle(p[0], p[1], p[2] * 0.8, p[2] * 0.8);

    strokeWeight(2);
    stroke(255, 255 - p[2] * 1.34);
    circle(p[0], p[1], p[2] * 0.6, p[2] * 0.6);

    p[2]++;
  });
}

class Particle {
  constructor(x, y) {
    this.pos = new p5.Vector(
      x || random(-50, width + 50),
      y || random(-50, height + 50)
    );
    this.color = random(theme.colors);
    this.r = random(0.25, 1);
  }

  update() {
    const dir = noise(this.pos.x / scale, this.pos.y / scale) * TAU * scale;
    this.pos.add(Math.cos(dir) / 2, Math.sin(dir) / 2);

    if (
      this.pos.x < -50 ||
      this.pos.x > width + 50 ||
      this.pos.y < -50 ||
      this.pos.y > height + 50
    )
      this.pos.set(random(-50, width + 50), random(-50, height + 50));
  }

  draw() {
    graphics.fill(this.color);
    graphics.circle(this.pos.x, this.pos.y, this.r);
  }
}

function createParticles() {
  scale = random(8e2, 2e3);
  theme = random([
    {
      colors: [
        "#FFFFFF",
        "#FFFFFF",
        "#FFFFFF",
        "#FFFFFF",
        "#cfe4f4",
        "#FFFFFF",
        "#c79b12",
        "#72b9f0",
        "#1265c7",
        "#eeedb6",
        "#2d5a8f",
        "#625cd4",
      ],
      background: "#150832",
    },
  ]);
  for (let i = 0; i < 500; i++) particles.push(new Particle());

  graphics = createGraphics(width, height);
  graphics.background(theme.background);
  graphics.noStroke();
}

