// Cyanotype (Blueprint) Webcam Effect
let seed = Math.random() * 30;
let yres = 30;
let xres = 20;
let capture; // Webcam video
let fbo1; // Framebuffer for effect

function setup() {
  createCanvas(800, 800, WEBGL);

  // Initialize webcam capture
  capture = createCapture(VIDEO);
  capture.size(width, height);
  capture.hide(); // Hide the original video element

  // Initialize framebuffer for the effect
  fbo1 = createFramebuffer();

  // Set random seed for consistent patterns between frames
  randomSeed(seed);
}

function draw() {
  // Clear background
  background(255);

  // Draw the video to the framebuffer with effect
  drawWebcamLayer();

  // Apply the layered effects
  push();
  translate(-width/2, -height/2);
  image(fbo1, 0, 0, width, height);
  pop();
  filter(BLUR, 2);

  blendMode(DIFFERENCE);
  filter(BLUR, 4);

  blendMode(MULTIPLY);
  filter(BLUR, 8);
}

function drawWebcamLayer() {
  let cBlue = color(17, 22, 40);
  let c2 = color(38, 99, 148);

  fbo1.begin();

  // First draw the webcam as base
  push();
  translate(-width/2, -height/2);
  // Draw the webcam with a blue tint
  tint(0, 0, 255, 150); // Apply blue tint
  image(capture, 0, 0, width, height);
  pop();

  // Apply the cyanotype pattern on top of webcam
  push();
  translate(-width/2, -height/2);
  for(let i = 0; i <= xres; i++) {
    let x = random(width);

    for(let j = 0; j <= yres; j++) {
      let xn1 = noise(random(x)) * 20;
      let yn = noise(j*0.1 + x*2) * yres/2;
      let n = (yn)/1;

      let y = j/yres * height;
      let y1 = (j+1)/yres * height;
      let yoff2 = yres/5/2;
      let yoff1 = yres/3;

      rectMode(CORNERS);

      // Draw the first layer of rectangles
      fill(cBlue, 125);
      noStroke();
      rect(x-n+2, y+yoff1, x+n-2, y1-yoff1);

      // Draw the second layer of rectangles
      fill(c2, 125);
      noStroke();
      rect(x-n, y+yoff2, x+n, y1-yoff2);
    }
  }
  pop();

  fbo1.end();
}

// The following is a compatibility function in case createFramebuffer is not available
// in the p5.js version being used
function createFramebuffer() {
  // Check if createFramebuffer is natively available
  if (typeof window.createFramebuffer === 'function') {
    return window.createFramebuffer();
  }

  // If not, create a graphics object as fallback
  let graphics = createGraphics(width, height, WEBGL);

  // Create a compatible API
  return {
    begin: function() {
      graphics.push();
      graphics.resetMatrix();
    },
    end: function() {
      graphics.pop();
    },
    // Make the graphics object usable as a texture
    valueOf: function() {
      return graphics;
    },
    // Allow using it directly in image() calls
    get texture() {
      return graphics;
    }
  };
}

