let seed;
let mySize, margin;
let palette;
let bgcolor = ["#ffffff", "#fefefe", "#fafafa"];

let video;
let handpose;
let predictions = [];
let fingers = []; // 存储所有手指关节位置
let handConfidence = 0; // 手部识别置信度
let lastValidHand = null; // 最后一个有效的手部位置

// 线程系统
let threads = [];
let THREAD_COUNT = 15; // 增加线条数量
let isHandVisible = false; // 是否检测到手

// 彩色主题
let colorScheme = [
  { colors: ["#FFB5E8", "#FF9CEE", "#FFCCF9", "#FCC2FF", "#F6A6FF"] },
  { colors: ["#A0E7E5", "#B4F8C8", "#FBE7C6", "#FFAEBC", "#A0C4FF"] },
  { colors: ["#FDFD96", "#FFFFD1", "#D0F4DE", "#E4C1F9", "#FCF6BD"] }
];

// 调试模式
let debugMode = true;
let frameRates = [];
let avgFPS = 0;

function setup() {
  seed = Math.random() * 10000;
  randomSeed(seed);

  // 创建画布
  mySize = min(windowWidth, windowHeight) * 0.9;
  createCanvas(mySize, mySize, WEBGL);
  perspective(PI/3, width/height, 5, 2000);

  // 设置色彩
  palette = random(colorScheme).colors.concat();
  background(random(bgcolor));
  frameRate(60);

  // 设置摄像头
  video = createCapture(VIDEO);
  video.size(640, 480);
  video.hide();

  // 设置手势识别
  const handposeOptions = {
    flipHorizontal: true, // 水平翻转以匹配镜像效果
    maxContinuousChecks: 5, // 增加连续检查次数
    detectionConfidence: 0.7, // 降低检测置信度以增加灵敏度
    scoreThreshold: 0.7, // 提高分数阈值以获得更准确的结果
    iouThreshold: 0.3, // 交并比阈值
  };

  handpose = ml5.handpose(video, handposeOptions, modelReady);

  // 创建线程
  for (let i = 0; i < THREAD_COUNT; i++) {
    threads.push(new Thread(
      0, 0, 0,
      random(palette),
      random(3, 8), // 线条粗细
      random(0.02, 0.08), // 弹性
      random(0.85, 0.95), // 阻尼
      random(20, 60) * (i + 1) // 偏移量
    ));
  }

  // 创建UI
  createUI();
}

function modelReady() {
  console.log("Handpose model loaded!");

  // 开始侦听预测
  handpose.on("predict", results => {
    predictions = results;

    // 更新手部可见性状态
    isHandVisible = predictions.length > 0;

    if (isHandVisible) {
      // 存储所有指尖位置
      const hand = predictions[0];
      fingers = [
        hand.annotations.thumb[3],    // 拇指尖
        hand.annotations.indexFinger[3], // 食指尖
        hand.annotations.middleFinger[3], // 中指尖
        hand.annotations.ringFinger[3],   // 无名指尖
        hand.annotations.pinky[3]      // 小指尖
      ];

      // 记录最后有效的手部数据
      lastValidHand = hand;
      handConfidence = hand.handInViewConfidence;
    }
  });
}

// 线程类
class Thread {
  constructor(x, y, z, color, weight, spring, damping, offset) {
    this.origin = createVector(0, 0, 0);
    this.pos = createVector(x, y, z);
    this.targetPos = createVector(x, y, z);
    this.vel = createVector(0, 0, 0);
    this.acc = createVector(0, 0, 0);

    this.color = color;
    this.weight = weight;
    this.spring = spring;
    this.damping = damping;
    this.offset = offset;

    // 路径历史记录，用于平滑显示
    this.history = [];
    this.historyLength = 5;
    for (let i = 0; i < this.historyLength; i++) {
      this.history.push(createVector(x, y, z));
    }
  }

  update(targetX, targetY, targetZ, fingerIndex) {
    // 添加一些随机性和独特运动，使线条看起来更有生命力
    let noiseVal = noise(frameCount/this.offset + fingerIndex * 10) * 40 - 20;

    // 根据手指位置设置目标
    this.targetPos.set(
      targetX + cos(frameCount/this.offset) * noiseVal,
      targetY + sin(frameCount/this.offset) * noiseVal,
      targetZ
    );

    // 计算弹簧力
    let direction = p5.Vector.sub(this.targetPos, this.pos);
    direction.mult(this.spring);
    this.acc.add(direction);

    // 应用加速度和阻尼
    this.vel.add(this.acc);
    this.vel.mult(this.damping);
    this.pos.add(this.vel);
    this.acc.mult(0); // 重置加速度

    // 更新历史记录
    this.history.push(createVector(this.pos.x, this.pos.y, this.pos.z));
    if (this.history.length > this.historyLength) {
      this.history.shift();
    }
  }

  display() {
    push();
    stroke(this.color);
    strokeWeight(this.weight);
    noFill();

    // 绘制平滑曲线而不是直线
    beginShape();
    vertex(this.origin.x, this.origin.y, this.origin.z);

    // 使用贝塞尔曲线平滑连接
    for (let i = 0; i < this.history.length; i++) {
      let p = this.history[i];
      curveVertex(p.x, p.y, p.z);
    }

    curveVertex(this.pos.x, this.pos.y, this.pos.z);
    endShape();

    // 在结尾处绘制一个小球
    push();
    translate(this.pos.x, this.pos.y, this.pos.z);
    noStroke();
    fill(this.color);
    sphere(this.weight * 0.8);
    pop();

    pop();
  }
}

function calculateHandCentroid() {
  if (!isHandVisible || !fingers.length) {
    return { x: 0, y: 0, z: 0 };
  }

  let xSum = 0, ySum = 0, zSum = 0;
  for (let finger of fingers) {
    xSum += finger[0];
    ySum += finger[1];
    zSum += finger[2] || 0;
  }

  return {
    x: map(xSum / fingers.length, 0, video.width, -width/2, width/2),
    y: map(ySum / fingers.length, 0, video.height, -height/2, height/2),
    z: 0 // 简化Z轴处理
  };
}

function draw() {
  // 背景
  background(random(bgcolor));

  // 计算手部信息
  let handInfo = {
    positions: [],
    centroid: { x: 0, y: 0, z: 0 }
  };

  // 处理手部数据
  if (isHandVisible && fingers.length) {
    // 映射所有手指位置到画布坐标
    handInfo.positions = fingers.map(finger => {
      return {
        x: map(finger[0], 0, video.width, -width/2, width/2),
        y: map(finger[1], 0, video.height, -height/2, height/2),
        z: 0
      };
    });

    // 计算手部中心点
    handInfo.centroid = calculateHandCentroid();
  } else if (lastValidHand) {
    // 使用最后一个有效的手部位置，但添加衰减效果
    const dampingFactor = 0.98;

    // 映射所有手指位置到画布坐标
    handInfo.positions = lastValidHand.annotations.thumb.map(joint => {
      return {
        x: map(joint[0], 0, video.width, -width/2, width/2) * dampingFactor,
        y: map(joint[1], 0, video.height, -height/2, height/2) * dampingFactor,
        z: 0
      };
    });

    handInfo.centroid = {
      x: handInfo.positions.reduce((sum, pos) => sum + pos.x, 0) / handInfo.positions.length,
      y: handInfo.positions.reduce((sum, pos) => sum + pos.y, 0) / handInfo.positions.length,
      z: 0
    };
  }

  // 更新并绘制所有线程
  push();
  ambientLight(100);
  pointLight(255, 255, 255, 0, 0, 200);

  // 轻微旋转场景使其更有3D效果
  rotateX(sin(frameCount * 0.01) * 0.1);
  rotateY(cos(frameCount * 0.01) * 0.1);

  for (let i = 0; i < threads.length; i++) {
    const thread = threads[i];

    // 如果有手的数据，使用不同手指控制不同线条
    if (handInfo.positions.length > 0) {
      const fingerIndex = i % 5; // 循环使用5个手指
      const position = handInfo.positions[fingerIndex];
      thread.update(position.x, position.y, position.z, fingerIndex);
    } else {
      // 没有手，使用波浪动画
      const angle = frameCount * 0.02 + i * 0.5;
      const radius = 100;
      const x = cos(angle) * radius;
      const y = sin(angle) * radius;
      thread.update(x, y, 0, i);
    }

    thread.display();
  }
  pop();

  // 绘制视频和调试信息
  if (debugMode) {
    drawDebugInfo(handInfo);
  }

  // 更新FPS统计
  updateFPS();
}

function drawDebugInfo(handInfo) {
  push();
  // 重置变换为2D模式
  camera();
  ortho();

  // 在左上角绘制摄像头图像
  push();
  translate(-width/2, -height/2);
  image(video, 10, 10, width/4, height/4);

  // 在视频上绘制手部关键点
  if (predictions.length > 0) {
    const hand = predictions[0];
    const scaleFactor = width/4 / video.width;

    // 设置样式
    strokeWeight(3);

    // 绘制手指关节
    for (let j = 0; j < hand.landmarks.length; j++) {
      const landmark = hand.landmarks[j];
      const [x, y] = landmark;

      // 将视频坐标映射到预览窗口
      const mappedX = x * scaleFactor + 10;
      const mappedY = y * scaleFactor + 10;

      // 为不同类型的关节使用不同颜色
      if (j === 8) { // 食指尖
        fill(255, 0, 0);
        stroke(255, 0, 0);
        ellipse(mappedX, mappedY, 10);
      } else if (j === 4) { // 拇指尖
        fill(0, 255, 0);
        stroke(0, 255, 0);
        ellipse(mappedX, mappedY, 10);
      } else if (j === 12) { // 中指尖
        fill(0, 0, 255);
        stroke(0, 0, 255);
        ellipse(mappedX, mappedY, 10);
      } else if (j === 16 || j === 20) { // 无名指和小指尖
        fill(255, 255, 0);
        stroke(255, 255, 0);
        ellipse(mappedX, mappedY, 10);
      } else {
        fill(255);
        stroke(255);
        ellipse(mappedX, mappedY, 5);
      }
    }
  }
  pop();

  // 显示状态信息
  fill(255);
  noStroke();
  textSize(14);
  textAlign(LEFT);

  let textY = height/2 - 100;
  text(`FPS: ${avgFPS.toFixed(1)}`, -width/2 + 20, textY);
  textY += 20;

  text(`手部检测: ${isHandVisible ? '检测到' : '未检测到'}`, -width/2 + 20, textY);
  textY += 20;

  if (isHandVisible && handConfidence) {
    text(`置信度: ${(handConfidence * 100).toFixed(1)}%`, -width/2 + 20, textY);
    textY += 20;
  }

  // 显示控制提示
  textY = height/2 - 60;
  text("按 'D' 键切换调试模式", -width/2 + 20, textY);
  textY += 20;
  text("按 'R' 键重置", -width/2 + 20, textY);

  pop();
}

function updateFPS() {
  // 计算FPS
  frameRates.push(frameRate());
  if (frameRates.length > 10) {
    frameRates.shift();
  }

  // 计算平均FPS
  avgFPS = frameRates.reduce((sum, rate) => sum + rate, 0) / frameRates.length;
}

function createUI() {
  // 调试模式切换按钮
  let debugButton = createButton('调试模式');
  debugButton.position(10, 10);
  debugButton.mousePressed(() => {
    debugMode = !debugMode;
  });

  // 重置按钮
  let resetButton = createButton('重置');
  resetButton.position(100, 10);
  resetButton.mousePressed(() => {
    // 重置所有线程
    for (let thread of threads) {
      thread.pos.set(0, 0, 0);
      thread.vel.set(0, 0, 0);
    }
  });

  // 线条数量滑块
  let threadSlider = createSlider(5, 30, THREAD_COUNT, 1);
  threadSlider.position(200, 10);
  threadSlider.style('width', '100px');
  threadSlider.input(() => {
    let newCount = threadSlider.value();

    // 调整线程数量
    if (newCount > threads.length) {
      // 添加更多线程
      for (let i = threads.length; i < newCount; i++) {
        threads.push(new Thread(
          0, 0, 0,
          random(palette),
          random(3, 8),
          random(0.02, 0.08),
          random(0.85, 0.95),
          random(20, 60) * (i + 1)
        ));
      }
    } else if (newCount < threads.length) {
      // 移除多余线程
      threads.splice(newCount);
    }

    THREAD_COUNT = newCount;
  });

  // 添加滑块标签
  let threadLabel = createElement('span', '线条数量:');
  threadLabel.position(200, 30);
  threadLabel.style('color', 'white');
}

function keyPressed() {
  if (key === 'd' || key === 'D') {
    debugMode = !debugMode;
  } else if (key === 'r' || key === 'R') {
    // 重置所有线程
    for (let thread of threads) {
      thread.pos.set(0, 0, 0);
      thread.vel.set(0, 0, 0);
    }
  }
}

