function draw() {
	randomSeed(seed);
	translate(-width / 2, -height / 2);
	let num_size = width / int(random(2, 5));
	var tileCountX = width / num_size + 1;
	var tileCountY = height / num_size + 1;
	var tileWidth = width / tileCountX;
	var tileHeight = height / tileCountY;

	for (var gridY = 0; gridY <= tileCountY; gridY++) {
		for (var gridX = 0; gridX <= tileCountX; gridX++) {
			let plus = random(-tileWidth / 2, tileWidth / 2);

			var posX = tileWidth * gridX;
			var posY = tileHeight * gridY;

			var x1 = tileWidth / 2;
			var y1 = tileHeight / 2;
			var x2 = 0;
			var y2 = 0;

			push();
			translate(posX, posY);

			for (var side = 0; side < 4; side++) {
				for (var i = 0; i < count; i++) {
					// move end point around the four sides of the tile
					switch (side) {
						case 0:
							x2 += tileWidth / count;
							y2 = 0;
							break;
						case 1:
							x2 = tileWidth;
							y2 += tileHeight / count;
							break;
						case 2:
							x2 -= tileWidth / count;
							y2 = tileHeight;
							break;
						case 3:
							x2 = 0;
							y2 -= tileHeight / count;
							break;
					}

					let stroke_brushes = brush.box()
					// let stroke_brushes = ["2H", "HB", "2B"]
					brush.set(random(stroke_brushes), random(color_set), random(1, 10))

					brush.stroke(random(color_set))
					brush.strokeWeight(random(1, 10))
					brush.noFill();

					brush.circle(x1 + plus, y1 + plus, random(1,10));
					let np1 = createVector(x1 + plus, y1 + plus);
					let np2 = createVector(x2, y2);
					let d1 = p5.Vector.dist(np1, np2);

					brush.beginStroke("curve", np1.x, np1.y);
					brush.segment(random(360), d1/random(1,2), 1.1);
					brush.segment(-random(360), d1/random(1,2), 2.1);
					brush.endStroke(random(360), 0.1);

					stroke(random(color_set))
					strokeWeight(random(1, 0.1))
					noFill();
					circle(np1.x, np1.y, random(1, 6));

				}
			}
			pop();
		}
	}
	if (frameCount == 2) {
		noLoop();
		noFill();
		stroke("#202020");
		strokeWeight(mySize / 100);
		blendMode(BLEND);
		rectMode(CORNER);
		rect(0, 0, width, height);
	}
}

