  bgm = loadSound(
    "bgmmm.mp3",
    () => console.log("Background music loaded"),
    (err) => console.error("Error loading bgmmm.mp3", err)
  );
  songs[0] = loadSound(
    "a3.mp3",
    () => console.log("a3.mp3 loaded"),
    (err) => console.error("Error loading a3.mp3", err)
  );

  songs[1] = loadSound("b3.mp3");
  songs[2] = loadSound("c3.mp3");
  songs[3] = loadSound("d3.mp3");
  songs[4] = loadSound("f3.mp3");
}

function setup() {
  createCanvas(800, 600);

  // 创建视频捕捉
  video = createCapture(VIDEO);
  video.size(640, 480);
  video.hide();

  flippedVideo = ml5.flipImage(video);
  handpose = ml5.handpose(video, modelReady);

  // 当检测到手势时，回调处理
  handpose.on("predict", gotHands);

  // 创建粒子效果
  createParticles();

  // 播放背景音乐
  if (bgm && bgm.isLoaded()) {
    bgm.loop();
    bgm.amp(0.2); // 设置背景音乐音量
  }
}

function modelReady() {
  console.log("Handpose model ready!");
}

function gotHands(results) {
  // 保存检测到的手势
  hands = results;
}

function draw() {
  background(0);
  push();
  translate(width, 0); // 水平翻转
  scale(-1, 1);
  image(video, 0, 0, width, height);
  pop();

  // 绘制粒子效果
  for (const p of particles) p.update();
  for (const p of particles) p.draw();
  image(graphics, 0, 0);

  // 手势处理和音频控制
  waterPaint();
}

function mapKeyToNote(keypointIndex) {
  // 将手指索引映射到对应音符
  const notes = {
    4: "a3",  // 拇指对应 a3.mp3
    8: "b3",  // 食指对应 b3.mp3
    12: "c3", // 中指对应 c3.mp3
    16: "d3", // 无名指对应 d3.mp3
    20: "f3"  // 小指对应 f3.mp3
  };
  return notes[keypointIndex];
}

function playNote(note) {
  const soundMap = {
    "a3": songs[0],
    "b3": songs[1],
    "c3": songs[2],
    "d3": songs[3],
    "f3": songs[4]
  };

  if (soundMap[note] && soundMap[note].isLoaded()) {
    soundMap[note].stop(); // 防止音频叠加
    soundMap[note].play();
  }
}

function waterPaint() {
  const fingertipIndices = [4, 8, 12, 16, 20];
  let threshold = 50; // 根据需要调整此阈值

  hands.forEach((hand) => {
    let wrist = hand.landmarks[0];

    fingertipIndices.forEach((fIndex) => {
      let fingertip = hand.landmarks[fIndex];
      let distanceToWrist = dist(wrist[0], wrist[1], fingertip[0], fingertip[1]);
      let isPressed = distanceToWrist < threshold;

      // 如果之前未按下，现在按下 -> 触发音效和粒子
      if (!fingerStates[fIndex] && isPressed) {
        const note = mapKeyToNote(fIndex);
        console.log(`Finger ${fIndex} pressed. Distance: ${distanceToWrist}, Note: ${note}`);
        playNote(note);

        const x = width - fingertip[0]; // 翻转后的手势坐标
        const y = fingertip[1];
        addParticle(x, y);
      }

      // 更新状态
      fingerStates[fIndex] = isPressed;
    });
  });
}

class Particle {
  constructor(x, y) {
    this.pos = createVector(
      x || random(-50, width + 50),
      y || random(-50, height + 50)
    );
    this.color = random(theme.colors);
    this.r = random(0.5, 2); // 增大粒子大小
    this.life = random(50, 150); // 每个粒子的寿命
  }

  update() {
    const dir =
      noise(this.pos.x / particleScale, this.pos.y / particleScale) *
      TWO_PI *
      particleScale;
    this.pos.add(createVector(cos(dir) / 2, sin(dir) / 2));
    this.life -= 1; // 减少寿命

    // 如果粒子超出边界，重置位置
    if (
      this.pos.x < -50 ||
      this.pos.x > width + 50 ||
      this.pos.y < -50 ||
      this.pos.y > height + 50 ||
      this.life <= 0
    ) {
      this.pos.set(random(-50, width + 50), random(-50, height + 50));
      this.life = random(50, 150);
    }
  }

  draw() {
    graphics.fill(this.color);
    graphics.circle(this.pos.x, this.pos.y, this.r);
  }
}

function createParticles() {
  particleScale = random(800, 2000);
  theme = random([
    {
      colors: [
        "#FFFFFF",
        "#FFFFFF",
        "#FFFFFF",
        "#FFFFFF",
        "#cfe4f4",
        "#FFFFFF",
        "#c79b12",
        "#72b9f0",
        "#1265c7",
        "#eeedb6",
        "#2d5a8f",
        "#625cd4",
      ],
      background: "#150832",
    },
  ]);

  for (let i = 0; i < 500; i++) particles.push(new Particle());

  graphics = createGraphics(width, height);
  graphics.background(theme.background);
  graphics.noStroke();
}

function addParticle(x, y) {
  particles.push(new Particle(x, y));
  if (particles.length > 300) particles.shift(); // 限制粒子数量
}

