let img;
let mosaicSize = 10;
const fixedWidth = 600; //Fix the image width
let scaledHeight; //scaled height of the image

function setup() {
  createCanvas(fixedWidth, 400); // Set initial canvas height as a placeholder
  background(200);
  textSize(16);
  fill(0);
  text("Please upload an image and click 'Generate Mosaic'", 10, 20);

  // Create file input for image upload
  let fileInput = createFileInput(handleFile);
  fileInput.position(10, 50);

  // Create slider to control mosaic size
  let slider = createSlider(5, 50, 10, 1);
  slider.position(10, 80);
  slider.input(() => {
    mosaicSize = slider.value();
  });

  // Create button to generate mosaic
  let generateBtn = createButton("Generate Mosaic");
  generateBtn.position(200, 50);
  generateBtn.mousePressed(() => {
    if (img) drawMosaic();
  });

  // Display current mosaic size
  let mosaicSizeText = createP("mosaicSize: " + mosaicSize);
  mosaicSizeText.position(10, 100);
  slider.input(() => {
    mosaicSize = slider.value();
    mosaicSizeText.html("mosaicSize: " + mosaicSize);
  });
}

function handleFile(file) {
  if (file.type === "image") {
    img = loadImage(file.data, () => {
      // Calculate the scaled height based on the original aspect ratio
      scaledHeight = (img.height / img.width) * fixedWidth;
      img.resize(fixedWidth, scaledHeight); // Resize image to fixed width, proportional height
      resizeCanvas(fixedWidth, scaledHeight); // Resize canvas to match new image dimensions
      background(200); // Clear background for new image
    });
  } else {
    alert("Please select a valid image file");
  }
}

function drawMosaic() {
  if (img && img.width > 0 && img.height > 0) {
    img.loadPixels(); // Load image pixel data
    for (let y = 0; y < img.height; y += mosaicSize) {
      for (let x = 0; x < img.width; x += mosaicSize) {
        let avgColor = getAverageColor(x, y, mosaicSize);
        fill(avgColor);
        noStroke();
        rect(x, y, mosaicSize, mosaicSize);
      }
    }
  } else {
    console.log("Image not fully loaded yet.");
  }
}

//Calculate the average color of the grid
function getAverageColor(x, y, size) {
  let r = 0,
    g = 0,
    b = 0,
    count = 0;
  for (let i = x; i < x + size && i < img.width; i++) {
    for (let j = y; j < y + size && j < img.height; j++) {
      let index = (j * img.width + i) * 4;
      r += img.pixels[index];
      g += img.pixels[index + 1];
      b += img.pixels[index + 2];
      count++;
    }
  }
  return color(r / count || 0, g / count || 0, b / count || 0);
}

