let capture;
let particles = [];

function setup() {
  createCanvas(640, 480);
  capture = createCapture(VIDEO);
  capture.size(640, 480);
  capture.hide();

  // 初始化粒子
  for (let y = 0; y < height; y += 10) {
    for (let x = 0; x < width; x += 10) {
      particles.push(new Particle(x, y));
    }
  }
}

function draw() {
  background(0);

  // 获取摄像头的像素数据
  capture.loadPixels();

  for (let i = 0; i < particles.length; i++) {
    let p = particles[i];
    let pixelIndex = (floor(p.y) * capture.width + floor(p.x)) * 4;

    if (capture.pixels[pixelIndex + 0] !== undefined) {
      let r = capture.pixels[pixelIndex + 0];
      let g = capture.pixels[pixelIndex + 1];
      let b = capture.pixels[pixelIndex + 2];
      let brightness = (r + g + b) / 3;

      // 更新粒子属性
      p.updateColor(color(r, g, b));
      p.updateSize(map(brightness, 0, 255, 2, 10));
    }

    // 显示粒子
    p.show();
  }
}

// 粒子类
class Particle {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.size = 5;
    this.col = color(255);
  }

  updateColor(col) {
    this.col = col;
  }

  updateSize(newSize) {
    this.size = newSize;
  }

  show() {
    noStroke();
    fill(this.col);
    ellipse(this.x, this.y, this.size);
  }
}

