  //frame
  fill(200, 250, 255);
  rect(0, 0, 750, 100);

  rect(0, 0, 100, 1000);

  rect(650, 0, 750, 1000);

  rect(0, 900, 750, 1000);

  // mouse interaction
  let gridSize = int(map(mouseX, 0, width, 45, 150));

  // Loop through the image in 2-dimensions
  video.loadPixels();
  for (let y = 0; y < video.height; y += gridSize) {
    for (let x = 0; x < video.width; x += gridSize) {
      //
      let index = (y * video.width + x) * 4;
      let r = video.pixels[index];
      let dia = map(r, 0, 255, gridSize, 2);

      // square
      fill(105, 225, 179);
      noStroke();
      square(x + gridSize / 2.5, y + gridSize / 2, dia);
    }
  }
}

