// sketch.js

let seed = Math.random() * 15283;
let t, num, radius;
let color_bg, color_setup2;
let v_planet = [];

let video, handposeModel, predictions = [];
let ctrlRotX = 0, ctrlRotY = 0, ctrlSpeed = 0.005;

const palettes = {
  bg: "#202020",
  sets: [
    "ffffff-171F26-4A5259-7B848C-AEB7BF",
    "D94389-4D578C-3791A6-3DF2D1-F28080",
    "F28D35-D96A29-A66641-D9B0A7-F2DAD8",
    "F2A7D8-473959-655A8C-9F8FD9-5979D9",
    "025951-012623-21BF92-73D9BC-0D0D0D"
  ].map(s=>s.split("-").map(a=>"#"+a))
};

function setup() {
  // 摄像头 & handpose
  video = createCapture(VIDEO);
  video.size(320,240);
  video.hide();
  handposeModel = ml5.handpose(video, ()=>console.log("Handpose ready"));
  handposeModel.on("predict", res=> predictions = res);

  // WEBGL 画布
  createCanvas(windowWidth, windowHeight, WEBGL);
  color_bg = palettes.bg;
  color_setup2 = random(palettes.sets);

  // 漩涡参数
  randomSeed(seed);
  num = int(random(10,30));
  t = 0;

  // 初始化行星点数组
  for (let i = 0; i < num; i++){
    v_planet.push(createVector());
  }

  updateRadius();
}

function windowResized(){
  resizeCanvas(windowWidth, windowHeight);
  updateRadius();
}

function updateRadius(){
  // 半径为屏幕最大边的 0.8 倍
  radius = max(windowWidth, windowHeight) * 0.8;
}

// 映射手势到旋转 & 速度
function updateHandControls() {
  if (!predictions.length) return;
  let h0 = predictions[0];
  let [ix0, iy0, iz0] = h0.landmarks[8]; // 食指尖
  ctrlRotY = map(ix0, 0, video.width, PI/2, -PI/2);
  ctrlRotX = map(iy0, 0, video.height, -PI/2, PI/2);

  if (predictions.length > 1){
    let h1 = predictions[1];
    let [ix1, iy1] = h1.landmarks[8];
    // 第二只手食指控制左右旋转
    ctrlRotY = map(ix1, 0, video.width, PI/2, -PI/2);
    let d = dist(ix0, iy0, ix1, iy1);
    ctrlSpeed = map(d, 0, sqrt(sq(video.width)+sq(video.height)), 0.02, 0.002, true);
  } else {
    // 单手：深度控制速度
    ctrlSpeed = map(iz0, -0.15, 0.15, 0.02, 0.002, true);
  }
}

// 在局部坐标绘制“毛茸茸”短线
function drawFuzzyPoint3D(col, density, size){
  stroke(col);
  strokeWeight(1);
  for (let k = 0; k < density; k++){
    let phi = random(TWO_PI), theta = random(TWO_PI);
    let dx = cos(phi)*sin(theta)*size;
    let dy = sin(phi)*sin(theta)*size;
    let dz = cos(theta)*size;
    line(0,0,0, dx,dy,dz);
  }
}

function draw() {
  // 背景：摄像头全屏平面
  background(0);
  push();
    translate(0,0,-500);
    texture(video);
    noStroke();
    plane(width*2, height*2);
  pop();

  // 更新手势控制
  updateHandControls();

  // 计算行星点
  randomSeed(seed);
  for (let i = 0; i < num; i++){
    let a = (TWO_PI/num)*i;
    let n = noise(a*0.1, frameCount*0.005);
    let x = radius * sin(a + t) * n * 0.5;
    let y = radius * cos(a + t) * n * 0.5;
    v_planet[i].set(x, y);
  }

  // 渲染 3D 漩涡
  push();
    rotateX(ctrlRotX);
    rotateY(ctrlRotY);

    for (let q = 0; q < 1/5; q += 2 * random(0.01, 0.02)){
      for (let j = 0; j < 1; j++){
        let n2 = noise(q*t, j*t, frameCount*0.01);
        rotateX(random(TAU)+sin(-t)/5 + q);
        rotateY(random(TAU)+cos(t)/5 + q);
        rotateZ(random(TAU)+sin(-t)/5 + q);

        noFill();
        for (let i = 0; i < num; i++){
          let col = random(color_setup2);

          // 球体 + 毛茸茸
          push();
            let vp = v_planet[i];
            translate(vp.x, vp.y, n2*50);
            rotateX(random(TAU)+t);
            rotateY(random(-TAU)+t);
            rotateZ(random(PI)+t);
            stroke(col);
            sphere(random(2,8));
            // 短线毛茸茸
            drawFuzzyPoint3D(col, 12, 12);
          pop();

          // 曲线
          stroke(col);
          strokeWeight(random(2.5));
          beginShape();
            curveVertex(0,0,0);
            curveVertex(vp.x*0.3, vp.y*0.3, n2*20);
            curveVertex(vp.x,    vp.y,    n2*40);
            curveVertex(vp.x*1.2, vp.y*1.2, n2*60);
            curveVertex(vp.x*1.5, vp.y*1.5, n2*80);
          endShape();
        }
      }
    }
  pop();

  t += ctrlSpeed;
}

