//Make blob: Dan Shiffman's tutorial - https://www.youtube.com/watch?v=rX5p-QRP6R4 
var zoff = 1;
var angle = 0;
var spinSpeed = 0.0025;
var noiseSpeed = 0.25;
var noiseLevel = 0.75;
var noiseGap;
var img;



function setup() {
  let cnv = createCanvas(750, 1000);

  noStroke();
  cnv.mousePressed(userStartAudio);
  input = new p5.AudioIn();
  input.start();
}

function draw() {
  background(30, 200, 250); 
  //image(img,0,0,750,1000)
  let soundLevel = input.getLevel(); 
  let noiseGap = soundLevel * 25 + 1;

  translate(width / 2, height / 2);
  rotate(-angle);

  noiseMax = 0.4;
  noStroke();

  // 中间的圆形
  push();
  translate(noiseGap, noiseGap);
  fill(255, 0, 0);
  makeBlob(soundLevel);
  pop();

  push();
  translate(-noiseGap, noiseGap);
  fill(0, 255, 0);
  makeBlob(soundLevel);
  pop();

  push();
  translate(-noiseGap, -noiseGap);
  fill(0, 0, 255);
  makeBlob(soundLevel);
  pop();

  angle += spinSpeed;
}

function makeBlob(soundLevel) {
  zoff += soundLevel * noiseSpeed + 0.001;
  blendMode(EXCLUSION);
  beginShape();
  for (let a = 0; a < TWO_PI; a += radians(1)) {
    let xoff = map(cos(a), -1, 1, 0, noiseLevel);
    let yoff = map(sin(a), -1, 1, 0, noiseLevel);
    let r = map(noise(xoff, yoff, zoff), 0, 1, 100, height * 0.6);
    let x = r * cos(a);
    let y = r * sin(a);
    vertex(x, y);
  }
  endShape(CLOSE);

  // 线条效果
  for (let a = 0; a < TWO_PI; a += 0.03) {
    let xoff = map(cos(a), -1, 1, 0, noiseMax);
    let yoff = map(sin(a), -1, 1, 0, noiseMax);
    let r = map(noise(xoff, yoff, zoff), 0, 1, 0, width / 1.1);
    let r2 = map(noise(xoff, yoff, zoff), 0, 1, -600, height / 1.1);
    let x = r * cos(a);
    let y = r2 * sin(a);

    stroke(30, 250, 255);
    line(x, y - 10, 0, 0);
  }

  zoff += 0.005;

  // 小圆圈
  for (let x = 0; x <= width; x += 300) {
    for (let y = 0; y <= height; y += 300) {
      let distance = dist(x, y, mouseX, mouseY);
      drawCircle(x, y, distance / 2);
    }
  }
}

function drawCircle(x, y, d) {
  push();
  noStroke();
  fill(x * 2, y / 3 + 200, x + 200);
  circle(x / 2, y / 2, d / 2);
  pop();
}

