let canvasWidth = 800;
let canvasHeight = 600;
let windStrength = 0.2;

const yarnColors = [
  '#FF5252', '#FF4081', '#E040FB', '#7C4DFF', '#536DFE', '#448AFF',
  '#40C4FF', '#18FFFF', '#64FFDA', '#69F0AE', '#B2FF59', '#EEFF41',
  '#FFFF00', '#FFD740', '#FFAB40', '#FF6E40', '#FF8A80', '#EA80FC',
  '#B388FF', '#8C9EFF', '#FFD180', '#84FFFF'
];

// 窗户参数
const windowParams = {
  x: 300,           // 窗户左上角 x 坐标
  y: 100,           // 窗户左上角 y 坐标
  width: 400,       // 窗户宽度
  height: 320,      // 窗户高度
  frameWidth: 30,   // 窗框宽度
  frameColor: '#3A2618', // 窗框颜色（棕色木质感）
  frameHighlight: '#5E4434', // 窗框高光颜色
  dividersColor: '#2A1A10', // 窗户分隔条颜色
}

class Particle {
  constructor(x, y, locked = false) {
    this.pos = createVector(x, y);
    this.prevPos = createVector(x, y);
    this.acc = createVector(0, 0);
    this.locked = locked;
    this.fuzzyEffect = random(0.8, 1.2);
  }

  addForce(f) {
    this.acc.add(f);
  }

  verlet() {
    if (this.locked) return;

    let vel = p5.Vector.sub(this.pos, this.prevPos);
    this.prevPos.set(this.pos);
    this.pos.add(vel).add(this.acc);
    this.acc.set(0, 0);
  }
}

class Spring {
  constructor(a, b, restLen, stiffness) {
    this.a = a;
    this.b = b;
    this.restLen = restLen;
    this.stiffness = stiffness;
  }

  satisfy() {
    let delta = p5.Vector.sub(this.b.pos, this.a.pos);
    let dist = delta.mag();
    let diff = (dist - this.restLen) / dist;
    let offset = delta.mult(0.5 * this.stiffness * diff);

    if (!this.a.locked) this.a.pos.add(offset);
    if (!this.b.locked) this.b.pos.sub(offset);
  }
}

class Yarn {
  constructor(x, y, length, thickness, color) {
    this.thickness = thickness * 1.5;
    this.color = color;
    this.colorObj = this.parseColor(color);
    this.particles = [];
    this.springs = [];
    this.init(x, y, length);
    this.fuzzySize = random(25, 40);
    this.fuzzyDensity = int(random(40, 50));
  }

  parseColor(hex) {
    const r = parseInt(hex.slice(1,3),16);
    const g = parseInt(hex.slice(3,5),16);
    const b = parseInt(hex.slice(5,7),16);
    return { r, g, b };
  }

  init(x, y, length) {
    let segs = 20, segLen = length/segs;
    for (let i = 0; i <= segs; i++) {
      let px = x + random(-5, 5);
      let py = y + length * (i/segs) + random(-5, 5);

      let p = new Particle(px + random(-5, 5), py + random(-5, 5), i === 0);
      this.particles.push(p);

      if (i > 0) {
        let a = this.particles[i-1];
        this.springs.push(new Spring(a, p, segLen, 0.8));
        if (i > 1) this.springs.push(new Spring(this.particles[i-2], p, segLen * 2, 0.2));
      }
    }
  }

  applyWind() {
    this.particles.forEach(p => {
      p.addForce(createVector(sin(frameCount * 0.02) * windStrength, 0.1));
    });
  }

  applyFingerInteraction(preds) {
    preds.forEach(hand => {
      [4, 8, 12, 16, 20].forEach(i => {
        let [fx, fy] = hand.landmarks[i];

        this.particles.forEach(p => {
          let d = dist(p.pos.x, p.pos.y, fx, fy);
          if (d < 50) {
            p.pos.add(p5.Vector.sub(createVector(fx, fy), p.pos).mult(0.3));
          }
        });
      });
    });
  }

  update() {
    this.particles.forEach(p => p.verlet());
    for (let i = 0; i < 5; i++) {
      this.springs.forEach(s => s.satisfy());
    }
  }

  display() {
    // 主干
    noFill();
    strokeWeight(this.thickness);
    stroke(this.color);
    beginShape();
    this.particles.forEach(p => vertex(p.pos.x, p.pos.y));
    endShape();

    // 毛茸茸效果
    this.particles.slice(0, -1).forEach((p, i) => {
      let q = this.particles[i+1];
      let d = p5.Vector.dist(p.pos, q.pos);
      let steps = constrain(int(d/8), 2, 12);

      for (let j = 0; j <= steps; j++) {
        let t = j/steps;
        let fp = createVector(
          lerp(p.pos.x, q.pos.x, t),
          lerp(p.pos.y, q.pos.y, t)
        );
        fp.add(random(-2, 2), random(-2, 2));

        let sf = this.particles[i].fuzzyEffect * map(sin(frameCount * 0.05 + i * 0.5), -1, 1, 0.9, 1.3);
        let c1 = `rgba(${this.colorObj.r},${this.colorObj.g},${this.colorObj.b},0.8)`;
        let c2 = `rgba(${this.colorObj.r},${this.colorObj.g},${this.colorObj.b},0.2)`;

        drawRadiatingLines(fp, this.fuzzyDensity, 1.2, this.fuzzySize * sf, c1, c2);
      }
    });
  }
}

class WovenGrid {
  constructor() {
    this.yarns = [];

    // 在窗户范围内增加窗帘毛线
    const {x, y, width, height} = windowParams;
    let spacing = 40; // 毛线间距

    // 在窗户范围内均匀分布毛线，从上方悬挂下来
    for (let xPos = x; xPos <= x + width; xPos += spacing) {
      // 随机选择颜色
      let color = random(yarnColors);
      // 创建毛线，从窗户顶部开始，长度略大于窗户高度
      this.yarns.push(
        new Yarn(
          xPos,        // 起点 x
          y - 20,      // 起点 y（稍微高于窗户顶部）
          height + 50, // 长度（稍长于窗户高度）
          random(8, 12), // 粗细
          color
        )
      );
    }
  }

  applyWind() {
    this.yarns.forEach(y => y.applyWind());
  }

  applyFingerInteraction(preds) {
    this.yarns.forEach(y => y.applyFingerInteraction(preds));
  }

  update() {
    this.yarns.forEach(y => y.update());
  }

  display() {
    this.yarns.forEach(y => y.display());
  }
}

function drawRadiatingLines(pt, d, w, s, c1, c2) {
  strokeWeight(w);

  for (let i = 0; i < d; i++) {
    let r = s * (0.7 + 0.3 * random());
    let a = random(TWO_PI);
    let ex = pt.x + r * cos(a);
    let ey = pt.y + r * sin(a);

    gradientLine(pt.x, pt.y, ex, ey, c1, c2);

    if (random() > 0.7) {
      let bp = createVector(
        lerp(pt.x, ex, random(0.3, 0.7)),
        lerp(pt.y, ey, random(0.3, 0.7))
      );

      let ba = a + random(-PI/4, PI/4);
      let bl = r * random(0.3, 0.5);
      let bx = bp.x + bl * cos(ba);
      let by = bp.y + bl * sin(ba);

      gradientLine(bp.x, bp.y, bx, by, c1, c2);
    }
  }
}

function gradientLine(x1, y1, x2, y2, c1, c2) {
  let g = drawingContext.createLinearGradient(x1, y1, x2, y2);
  g.addColorStop(0, c1);
  g.addColorStop(1, c2);
  drawingContext.strokeStyle = g;
  line(x1, y1, x2, y2);
};

// 条纹风格参数
const stripedStyle = {
  lineSpacing: 4,       // 条纹间距
  lineThickness: 1.5,   // 条纹线条粗细
  variation: 2,         // 线条变化幅度
};

// 背景和场景元素
let bgCanvas;
let flowers = [];
let trees = [];
let grassPatches = [];
let leaves = [];
let butterflies = [];
let flowerPots = [];

let video;
let handposeModel;
let predictions = [];
let wovenGrid;

function setup() {
  createCanvas(canvasWidth, canvasHeight);

  // 初始化背景和场景元素
  createBackgroundElements();

  // 初始化摄像头和手势识别
  video = createCapture(VIDEO);
  video.size(windowParams.width, windowParams.height);
  video.hide();

  // 加载手势模型
  handposeModel = ml5.handpose(video, modelReady);
  handposeModel.on('predict', results => predictions = results);

  // 初始化窗帘
  wovenGrid = new WovenGrid();
}

function createBackgroundElements() {
  // 创建背景画布
  bgCanvas = createGraphics(canvasWidth, canvasHeight);

  // 绘制天空和地面
  drawStripedSky();

  // 创建树木
  createTrees();

  // 创建草地
  createGrassPatches();

  // 创建装饰叶子
  createLeaves();

  // 创建花盆
  createFlowerPots();

  // 创建蝴蝶
  for (let i = 0; i < 5; i++) {
    butterflies.push(new Butterfly());
  }
}

function drawStripedSky() {
  // 用条纹风格绘制天空
  let skyBlue1 = color(180, 225, 255);
  let skyBlue2 = color(150, 200, 240);

  drawStripedArea(bgCanvas, 0, 0, canvasWidth, canvasHeight * 0.6, skyBlue1, skyBlue2, true);
}

function createTrees() {
  // 创建条纹风格的树木
  let treePositions = [
    { x: 100, width: 40, height: 400 },
    { x: 200, width: 35, height: 380 },
    { x: 350, width: 50, height: 420 },
    { x: 500, width: 45, height: 390 },
    { x: 650, width: 30, height: 370 }
  ];

  for (let tree of treePositions) {
    trees.push({
      x: tree.x,
      width: tree.width,
      height: tree.height,
      branches: generateBranches(3, 5)
    });
  }

  // 绘制所有树木
  for (let tree of trees) {
    drawStripedTree(
      tree.x, 
      canvasHeight * 0.6 - tree.height + 50, 
      tree.width, 
      tree.height, 
      tree.branches
    );
  }
}

function generateBranches(min, max) {
  let branchCount = floor(random(min, max + 1));
  let branches = [];

  for (let i = 0; i < branchCount; i++) {
    branches.push({
      heightPercent: random(0.2, 0.8),  // 从树干的什么高度位置分出
      angle: random(-PI/4, PI/4),       // 分枝角度
      length: random(0.3, 0.6),         // 相对于树干的长度比例
      width: random(0.4, 0.8)           // 相对于树干的宽度比例
    });
  }

  return branches;
}

function drawStripedTree(x, y, width, height, branches) {
  // 树干颜色
  let trunkBrown1 = color(150, 100, 60);
  let trunkBrown2 = color(120, 80, 50);

  // 绘制树干
  drawStripedArea(
    bgCanvas, 
    x - width/2, 
    y, 
    width, 
    height, 
    trunkBrown1, 
    trunkBrown2, 
    false  // 水平条纹
  );

  // 绘制分枝
  for (let branch of branches) {
    let branchY = y + height * branch.heightPercent;
    let branchLength = height * branch.length;
    let branchWidth = width * branch.width;

    bgCanvas.push();
    bgCanvas.translate(x, branchY);
    bgCanvas.rotate(branch.angle);

    drawStripedArea(
      bgCanvas,
      0,
      0,
      branchLength,
      branchWidth,
      trunkBrown1,
      trunkBrown2,
      false
    );

    bgCanvas.pop();
  }
}

function createGrassPatches() {
  // 定义不同颜色的草地区域
  let grassColors = [
    { color1: color(200, 230, 100), color2: color(180, 210, 80) },    // 黄绿色
    { color1: color(100, 180, 100), color2: color(80, 160, 80) },     // 深绿色
    { color1: color(150, 210, 120), color2: color(130, 190, 100) },   // 中绿色
    { color1: color(220, 150, 240), color2: color(200, 130, 220) },   // 紫色
    { color1: color(240, 220, 100), color2: color(220, 200, 80) },    // 黄色
    { color1: color(100, 180, 220), color2: color(80, 160, 200) }     // 蓝色
  ];

  // 创建多个不规则形状的草地
  for (let i = 0; i < 15; i++) {
    let patch = {
      points: [],
      colorPair: random(grassColors)
    };

    // 为每个草地创建不规则多边形
    let centerX = random(canvasWidth);
    let centerY = random(canvasHeight * 0.6, canvasHeight);
    let radius = random(50, 150);
    let pointCount = floor(random(5, 10));

    for (let j = 0; j < pointCount; j++) {
      let angle = j * TWO_PI / pointCount;
      let r = radius * (0.7 + 0.3 * sin(angle * 3));
      let px = centerX + r * cos(angle);
      let py = centerY + r * sin(angle);

      patch.points.push({ x: px, y: py });
    }

    grassPatches.push(patch);
  }

  // 绘制所有草地
  bgCanvas.push();
  bgCanvas.translate(0, canvasHeight * 0.6);

  // 先绘制一个条纹背景层
  let baseLightGreen = color(180, 230, 150);
  let baseDarkGreen = color(160, 210, 130);
  drawStripedArea(
    bgCanvas,
    0,
    0,
    canvasWidth,
    canvasHeight * 0.4,
    baseLightGreen,
    baseDarkGreen,
    true  // 垂直条纹
  );

  // 然后绘制所有的草地块
  for (let patch of grassPatches) {
    drawStripedPatch(
      patch.points,
      patch.colorPair.color1,
      patch.colorPair.color2,
      true  // 垂直条纹
    );
  }

  bgCanvas.pop();
}

function drawStripedPatch(points, color1, color2, vertical) {
  // 计算区域的边界
  let minX = Infinity, maxX = -Infinity;
  let minY = Infinity, maxY = -Infinity;

  for (let pt of points) {
    minX = min(minX, pt.x);
    maxX = max(maxX, pt.x);
    minY = min(minY, pt.y);
    maxY = max(maxY, pt.y);
  }

  // 创建用于裁剪的路径
  bgCanvas.beginShape();
  for (let pt of points) {
    bgCanvas.vertex(pt.x, pt.y);
  }
  bgCanvas.endShape(CLOSE);

  // 将这个形状用作裁剪区域
  bgCanvas.drawingContext.save();
  bgCanvas.drawingContext.clip();

  // 在裁剪区域内绘制条纹
  let spacing = stripedStyle.lineSpacing;

  if (vertical) {
    // 垂直条纹
    for (let x = minX; x < maxX; x += spacing) {
      bgCanvas.strokeWeight(stripedStyle.lineThickness);
      bgCanvas.stroke(x % (spacing * 2) < spacing ? color1 : color2);
      bgCanvas.line(
        x + random(-stripedStyle.variation, stripedStyle.variation),
        minY,
        x + random(-stripedStyle.variation, stripedStyle.variation),
        maxY
      );
    }
  } else {
    // 水平条纹
    for (let y = minY; y < maxY; y += spacing) {
      bgCanvas.strokeWeight(stripedStyle.lineThickness);
      bgCanvas.stroke(y % (spacing * 2) < spacing ? color1 : color2);
      bgCanvas.line(
        minX,
        y + random(-stripedStyle.variation, stripedStyle.variation),
        maxX,
        y + random(-stripedStyle.variation, stripedStyle.variation)
      );
    }
  }

  // 恢复裁剪区域
  bgCanvas.drawingContext.restore();
}

function drawStripedArea(canvas, x, y, w, h, color1, color2, vertical) {
  let spacing = stripedStyle.lineSpacing;

  if (vertical) {
    // 垂直条纹
    for (let i = 0; i < w; i += spacing) {
      canvas.strokeWeight(stripedStyle.lineThickness);
      canvas.stroke(i % (spacing * 2) < spacing ? color1 : color2);
      canvas.line(
        x + i + random(-stripedStyle.variation, stripedStyle.variation),
        y,
        x + i + random(-stripedStyle.variation, stripedStyle.variation),
        y + h
      );
    }
  } else {
    // 水平条纹
    for (let i = 0; i < h; i += spacing) {
      canvas.strokeWeight(stripedStyle.lineThickness);
      canvas.stroke(i % (spacing * 2) < spacing ? color1 : color2);
      canvas.line(
        x,
        y + i + random(-stripedStyle.variation, stripedStyle.variation),
        x + w,
        y + i + random(-stripedStyle.variation, stripedStyle.variation)
      );
    }
  }
}

function createLeaves() {
  // 创建装饰叶子
  for (let i = 0; i < 60; i++) {
    let side = random() > 0.5;
    let x, y;

    if (side) {
      // 左侧叶子
      x = random(50, windowParams.x - 10);
      y = random(windowParams.y - 50, windowParams.y + windowParams.height + 100);
    } else {
      // 右侧叶子
      x = random(windowParams.x + windowParams.width + 10, canvasWidth - 50);
      y = random(windowParams.y - 50, windowParams.y + windowParams.height + 100);
    }

    leaves.push({
      x: x,
      y: y,
      size: random(30, 60),
      rotation: random(TWO_PI),
      color: color(random(30, 100), random(150, 220), random(30, 100), 200)
    });
  }

  // 绘制所有叶子
  for (let leaf of leaves) {
    drawLeaf(leaf.x, leaf.y, leaf.size, leaf.rotation, leaf.color);
  }
}

function drawLeaf(x, y, size, rotation, leafColor) {
  // 在背景画布上绘制叶子
  bgCanvas.push();
  bgCanvas.translate(x, y);
  bgCanvas.rotate(rotation);

  // 叶子基础形状
  bgCanvas.noStroke();
  bgCanvas.fill(leafColor);

  // 开始绘制叶子形状
  bgCanvas.beginShape();
  for (let i = 0; i < TWO_PI; i += 0.1) {
    let r = size * (1 + sin(i * 2) * 0.3) * 0.5;
    let px = r * cos(i);
    let py = r * sin(i);
    bgCanvas.vertex(px, py);
  }
  bgCanvas.endShape(CLOSE);

  // 叶脉 - 使用条纹风格
  bgCanvas.stroke(0, 100);
  bgCanvas.strokeWeight(1);
  bgCanvas.line(0, 0, size * 0.5, 0);

  for (let a = -PI/4; a <= PI/4; a += PI/8) {
    let len = size * 0.5 * cos(a * 2);
    bgCanvas.line(0, 0, len * cos(a), len * sin(a));
  }

  bgCanvas.pop();
}

function createFlowerPots() {
  // 创建窗户下方的花盆
  flowerPots = [
    { x: windowParams.x - 60, y: windowParams.y + windowParams.height + 20, width: 70, height: 80 },
    { x: windowParams.x + windowParams.width - 10, y: windowParams.y + windowParams.height + 30, width: 80, height: 70 }
  ];

  // 绘制所有花盆
  for (let pot of flowerPots) {
    drawFlowerPot(pot.x, pot.y, pot.width, pot.height);
  }
}

function drawFlowerPot(x, y, w, h) {
  // 在背景画布上绘制花盆
  // 花盆底色
  bgCanvas.noStroke();
  bgCanvas.fill(165, 110, 90); // 陶土色
  bgCanvas.rect(x + w*0.1, y, w*0.8, h*0.8, 5, 5, 0, 0);

  // 花盆顶部
  bgCanvas.fill(185, 130, 110);
  bgCanvas.rect(x, y, w, h*0.2, 5);

  // 花盆纹理 - 使用条纹风格
  let potColor1 = color(165, 110, 90);
  let potColor2 = color(145, 90, 70);

  // 在花盆上添加条纹
  drawStripedArea(
    bgCanvas,
    x + w*0.1,
    y + h*0.2,
    w*0.8,
    h*0.6,
    potColor1,
    potColor2,
    false  // 水平条纹
  );

  // 花朵
  let flowerCount = int(random(3, 6));
  let centerX = x + w/2;
  let centerY = y - h*0.1;

  // 花茎 - 条纹风格
  let stemColor1 = color(100, 180, 100);
  let stemColor2 = color(80, 160, 80);

  for (let i = 0; i < flowerCount; i++) {
    let fx = centerX + random(-w*0.3, w*0.3);
    let fy = centerY + random(-h*0.15, h*0.1);
    let stemHeight = random(h*0.5, h*0.7);

    // 绘制茎
    drawStripedArea(
      bgCanvas,
      fx - 2,
      fy,
      4,
      stemHeight,
      stemColor1,
      stemColor2,
      false
    );

    // 绘制花
    let size = random(15, 25);
    let petalCount = floor(random(5, 8));

    // 随机选择花色
    let petalColor = color(
      random(200, 255),
      random(100, 200),
      random(100, 220)
    );

    let centerColor = color(255, 230, 100);

    drawStripedFlower(fx, fy, size, petalCount, petalColor, centerColor);
  }
}

function drawStripedFlower(x, y, size, petalCount, petalColor, centerColor) {
  bgCanvas.push();
  bgCanvas.translate(x, y);

  // 花瓣
  let petalLength = size * 0.8;
  let petalWidth = size * 0.3;

  for (let i = 0; i < petalCount; i++) {
    let angle = i * TWO_PI / petalCount;

    bgCanvas.push();
    bgCanvas.rotate(angle);
    bgCanvas.translate(0, -size * 0.5);

    // 为每个花瓣添加条纹
    let petalColor1 = petalColor;
    let petalColor2 = color(
      red(petalColor) * 0.9,
      green(petalColor) * 0.9,
      blue(petalColor) * 0.9
    );

    drawStripedArea(
      bgCanvas,
      -petalWidth / 2,
      0,
      petalWidth,
      petalLength,
      petalColor1,
      petalColor2,
      true  // 垂直条纹
    );

    bgCanvas.pop();
  }

  // 花蕊
  let centerSize = size * 0.4;
  bgCanvas.fill(centerColor);
  bgCanvas.noStroke();
  bgCanvas.ellipse(0, 0, centerSize, centerSize);

  // 花蕊纹理
  bgCanvas.stroke(color(
    red(centerColor) * 0.8,
    green(centerColor) * 0.8,
    blue(centerColor) * 0.8
  ));
  bgCanvas.strokeWeight(1);

  for (let i = 0; i < 12; i++) {
    let angle = random(TWO_PI);
    let r = random(centerSize * 0.2, centerSize * 0.4);
    bgCanvas.point(r * cos(angle), r * sin(angle));
  }

  bgCanvas.pop();
}

function modelReady() {
  console.log('Handpose model loaded');
}

function draw() {
  // 绘制背景场景
  image(bgCanvas, 0, 0);

  // 绘制窗框
  drawWindow();

  // 绘制摄像头画面在窗户内
  image(video, windowParams.x, windowParams.y, windowParams.width, windowParams.height);

  // 更新和绘制动态元素
  updateDynamicElements();

  // 更新和绘制窗帘
  wovenGrid.applyWind();
  wovenGrid.applyFingerInteraction(predictions);
  wovenGrid.update();
  wovenGrid.display();

  // 绘制手指点
  drawHandPoints();
}

function updateDynamicElements() {
  // 更新和绘制蝴蝶
  for (let butterfly of butterflies) {
    butterfly.update();
    butterfly.display();
  }
}

function drawWindow() {
  // 窗户参数
  const {x, y, width, height, frameWidth, frameColor, frameHighlight, dividersColor} = windowParams;

  // 绘制窗框
  noStroke();
  fill(frameColor);
  // 外框
  rect(x - frameWidth, y - frameWidth, width + frameWidth * 2, height + frameWidth * 2);
  // 内框（擦除中间部分）
  fill(200);
  rect(x, y, width, height);

  // 添加窗框纹理和高光
  drawingContext.shadowBlur = 0;
  noStroke();

  // 绘制窗框木纹
  drawWoodTexture(x - frameWidth, y - frameWidth, frameWidth, height + frameWidth * 2); // 左边框
  drawWoodTexture(x + width, y - frameWidth, frameWidth, height + frameWidth * 2); // 右边框
  drawWoodTexture(x - frameWidth, y - frameWidth, width + frameWidth * 2, frameWidth); // 上边框
  drawWoodTexture(x - frameWidth, y + height, width + frameWidth * 2, frameWidth); // 下边框

  // 窗户分隔条
  fill(dividersColor);
  // 水平分隔条
  rect(x, y + height/2 - 5, width, 10);
  // 垂直分隔条
  rect(x + width/2 - 5, y, 10, height);

  // 窗框高光
  noFill();
  stroke(frameHighlight);
  strokeWeight(2);
  // 内框高光
  rect(x + 3, y + 3, width - 6, height - 6);
  // 外框高光
  rect(x - frameWidth + 3, y - frameWidth + 3, width + frameWidth * 2 - 6, height + frameWidth * 2 - 6);
}

function drawWoodTexture(x, y, width, height) {
  fill(windowParams.frameColor);
  rect(x, y, width, height);

  // 添加木纹纹理
  noFill();
  stroke(windowParams.frameHighlight);
  strokeWeight(1);

  let count = width > height ? width / 5 : height / 5;
  for (let i = 0; i < count; i++) {
    let offset = map(sin(i * 0.2), -1, 1, -2, 2);

    if (width > height) {
      // 水平木纹
      let yPos = y + map(i, 0, count, 0, height);
      line(x + offset, yPos, x + width - offset, yPos);
    } else {
      // 垂直木纹
      let xPos = x + map(i, 0, count, 0, width);
      line(xPos, y + offset, xPos, y + height - offset);
    }
  }
}

function drawHandPoints() {
  noStroke();
  fill(255, 100, 100);
  const tips = [4, 8, 12, 16, 20]; // 手指尖点索引

  predictions.forEach(hand => {
    tips.forEach(i => {
      const [x, y] = hand.landmarks[i];
      ellipse(x, y, 12, 12);
    });
  });
}

class Butterfly {
  constructor() {
    this.pos = createVector(random(canvasWidth), random(canvasHeight));
    this.vel = createVector(0, 0);
    this.acc = createVector(0, 0);
    this.targetPos = createVector(random(canvasWidth), random(canvasHeight));
    this.wingAngle = 0;
    this.wingSpeed = random(0.15, 0.25);
    this.size = random(10, 20);
    this.wingColor = color(
      random(150, 255),
      random(100, 255),
      random(150, 255),
      200
    );
    this.idleTimer = 0;
    this.idleDuration = random(50, 150);

    // 条纹效果的翅膀
    this.hasStripedWings = random() > 0.3; // 70% 的蝴蝶有条纹翅膀
    this.wingStripeColor1 = this.wingColor;
    this.wingStripeColor2 = color(
      red(this.wingColor) * 0.8,
      green(this.wingColor) * 0.8,
      blue(this.wingColor) * 0.8,
      180
    );
  }

  update() {
    // 目标寻找行为
    if (this.idleTimer > 0) {
      // 停留
      this.idleTimer--;
      this.wingAngle += this.wingSpeed * 0.2; // 慢速扇动翅膀
    } else if (p5.Vector.dist(this.pos, this.targetPos) < 20) {
      // 到达目标，设置新目标或停留
      if (random() < 0.7) {
        this.idleTimer = this.idleDuration;
      } else {
        this.setNewTarget();
      }
    } else {
      // 向目标飞行
      let desired = p5.Vector.sub(this.targetPos, this.pos);
      desired.setMag(2);

      let steer = p5.Vector.sub(desired, this.vel);
      steer.limit(0.1);

      this.acc.add(steer);
      this.wingAngle += this.wingSpeed; // 快速扇动翅膀
    }

    // 运动更新
    this.vel.add(this.acc);
    this.vel.limit(2);
    this.pos.add(this.vel);
    this.acc.mult(0);

    // 边界检查
    if (this.pos.x < 0 || this.pos.x > canvasWidth || 
        this.pos.y < 0 || this.pos.y > canvasHeight) {
      this.setNewTarget();
    }
  }

  setNewTarget() {
    // 避开窗户区域的新目标
    let newX, newY;
    do {
      newX = random(canvasWidth);
      newY = random(canvasHeight);
    } while (
      newX > windowParams.x - 50 && 
      newX < windowParams.x + windowParams.width + 50 &&
      newY > windowParams.y - 50 && 
      newY < windowParams.y + windowParams.height + 50
    );

    this.targetPos.set(newX, newY);
  }

  display() {
    push();
    translate(this.pos.x, this.pos.y);

    // 根据速度方向旋转
    let angle = atan2(this.vel.y, this.vel.x);
    rotate(angle);

    // 绘制翅膀
    let wingY = sin(this.wingAngle) * this.size;

    // 条纹翅膀或普通翅膀
    if (this.hasStripedWings) {
      this.drawStripedWings(wingY);
    } else {
      this.drawNormalWings(wingY);
    }

    // 身体
    fill(50);
    noStroke();
    ellipse(0, 0, this.size * 0.3, this.size * 1.2);

    // 触角
    stroke(50);
    strokeWeight(1);
    line(0, -this.size * 0.6, -this.size * 0.3, -this.size * 0.9);
    line(0, -this.size * 0.6, this.size * 0.3, -this.size * 0.9);

    pop();
  }

  drawNormalWings(wingY) {
    fill(this.wingColor);
    noStroke();

    // 后翅
    push();
    translate(-this.size * 0.2, 0);
    ellipse(-this.size * 0.3, wingY * 0.7, this.size * 1.2, this.size * 2);
    ellipse(this.size * 0.3, -wingY * 0.7, this.size * 1.2, this.size * 2);
    pop();

    // 前翅
    ellipse(-this.size * 0.5, wingY, this.size, this.size * 1.5);
    ellipse(this.size * 0.5, -wingY, this.size, this.size * 1.5);
  }

  drawStripedWings(wingY) {
    // 使用条纹效果绘制翅膀
    noFill();

    // 后翅
    push();
    translate(-this.size * 0.2, 0);

    // 左后翅
    push();
    translate(-this.size * 0.3, wingY * 0.7);
    this.drawWingStripes(this.size * 1.2, this.size * 2);
    pop();

    // 右后翅
    push();
    translate(this.size * 0.3, -wingY * 0.7);
    this.drawWingStripes(this.size * 1.2, this.size * 2);
    pop();

    pop();

    // 左前翅
    push();
    translate(-this.size * 0.5, wingY);
    this.drawWingStripes(this.size, this.size * 1.5);
    pop();

    // 右前翅
    push();
    translate(this.size * 0.5, -wingY);
    this.drawWingStripes(this.size, this.size * 1.5);
    pop();
  }

  drawWingStripes(width, height) {
    // 绘制椭圆形状的条纹翅膀
    let stripesCount = floor(width / 3);

    for (let i = 0; i < stripesCount; i++) {
      let x = map(i, 0, stripesCount, -width/2, width/2);

      stroke(i % 2 === 0 ? this.wingStripeColor1 : this.wingStripeColor2);
      strokeWeight(2);

      // 计算当前位置的椭圆高度
      let y1 = -sqrt(1 - sq(x / (width/2))) * (height/2);
      let y2 = sqrt(1 - sq(x / (width/2))) * (height/2);

      // 添加一些随机变化使条纹更自然
      let offset = random(-1, 1);
      line(x + offset, y1, x + offset, y2);
    }
  }
}

