let seed;
let th = 0, seg = 0.01;
let mySize;
let colors1 = ["#ACEBD4", "#ACDEEB", "#21D8EA", "#3CC1FF", "#6DE4AA"];
let colors2 = ["#CEA7EB00", "#3890FF00", "#C330C600", "#D5FF5200", "#A6DBF700"];
let colorbg = ["#AEF6D2"];
let colorbg2 = ["#C1CCEA"];
let organisms = [];
let bubbles = [];
let overAllTexture;

class Organism {
  constructor() {
    this.type = floor(random(5));
    this.size = random(25, 60);
    this.x = random(-width/2, width/2);
    this.y = random(-height/2, height/2);
    this.baseColor = color(random(colors1));
    this.speedX = 0;
    this.speedY = 0;
    this.noiseScale = random(0.005, 0.015);
    this.angleOffset = random(TWO_PI);
    this.wiggleOffset = random(10);
    this.rotation = random(TWO_PI);
    this.segments = floor(random(6, 8));
    this.flagella = floor(random(2, 4));
  }

  update() {
    let noiseVal = noise(
      this.x * this.noiseScale,
      this.y * this.noiseScale,
      frameCount*0.01
    );
    this.speedX = cos(noiseVal * TWO_PI + this.angleOffset) * 0.3;
    this.speedY = sin(noiseVal * TWO_PI + this.angleOffset) * 0.3;

    this.x += this.speedX + sin(frameCount*0.03 + this.wiggleOffset)*1.5;
    this.y += this.speedY + cos(frameCount*0.02)*1.2;
    this.rotation += 0.005;

    if (abs(this.x) > width/2*0.9) {
      this.speedX *= -0.5;
      this.x = constrain(this.x, -width/2*0.9, width/2*0.9);
      this.angleOffset += random(-0.5, 0.5);
    }
    if (abs(this.y) > height/2*0.9) {
      this.speedY *= -0.5;
      this.y = constrain(this.y, -height/2*0.9, height/2*0.9);
      this.angleOffset += random(-0.5, 0.5);
    }
  }

  display() {
    push();
    translate(this.x, this.y);
    rotate(this.rotation);

    let pulseSize = this.size * (1 + sin(frameCount*0.03)*0.1);
    let currentColor = this.baseColor;
    currentColor.setAlpha(80);

    drawingContext.shadowColor = currentColor;
    drawingContext.shadowBlur = 15;

    switch(this.type) {
      case 0:
        this.displayJellyfish(pulseSize, currentColor);
        break;
      case 1:
        this.displaySparkles(pulseSize);
        break;
      case 2:
        this.displayFish(pulseSize);
        break;
      case 3:
        this.displayMicrobial();
        break;
      case 4:
        this.displayGlowJellyfish(pulseSize);
        break;
    }
    pop();
  }

  // 水母型
  displayJellyfish(size, col) {
    fill(col);
    noStroke();
    ellipse(0, 0, size*0.8, size*1.2);
    for(let i=0; i<8; i++) {
      let angle = PI/4 * i;
      stroke(col);
      strokeWeight(2);
      line(
        cos(angle)*size*0.4,
        sin(angle)*size*0.4,
        cos(angle)*size*1.2 + random(-2,2),
        sin(angle)*size*1.2 + random(-2,2)
      );
    }
  }

  // 发光粒子型
  displaySparkles(size) {
    for(let i=0; i<20; i++){
      let angle = random(TWO_PI);
      let radius = random(size/2);
      fill(360, 0, 100, random(50,80));
      noStroke();
      ellipse(
        cos(angle)*radius,
        sin(angle)*radius,
        random(2,5)
      );
    }
  }

  // 深海鱼型
  displayFish(size) {
    fill(30, 80, 80, 80);
    noStroke();
    beginShape();
    vertex(-size/2, 0);
    quadraticVertex(
      0, -size/3,
      size/2, 0
    );
    quadraticVertex(
      0, size/3,
      -size/2, 0
    );
    endShape();

    // 鱼鳍
    fill(200, 80, 100, 80);
    triangle(
      size/4, 0,
      size/2, -size/6,
      size/2, size/6
    );
  }

  // 微生物群
  displayMicrobial() {
    for(let i=0; i<5; i++){
      let angle = random(TWO_PI);
      let radius = random(this.size/3);
      fill(
        random(180,240), 
        random(50,80), 
        random(70,90), 
        80
      );
      ellipse(
        cos(angle)*radius,
        sin(angle)*radius,
        random(10,20)
      );
    }
  }

  // 发光水母
  displayGlowJellyfish(size) {
    let tentacleCount = 12;
    for(let i=0; i<tentacleCount; i++){
      let angle = TWO_PI/tentacleCount * i;
      let tx = cos(angle) * size;
      let ty = sin(angle) * size;
      stroke(200, 100, 100, 80);
      line(0,0,tx,ty);
      fill(200, 100, 100, 80);
      ellipse(tx, ty, 8, 8);
    }
  }
}

function setup() {
  seed = random(1000);
  mySize = min(windowWidth, windowHeight);
  createCanvas(windowWidth, windowHeight);
  colorMode(HSB, 360, 100, 100, 100);

  for(let i=0; i<25; i++){
    organisms.push(new Organism());
  }
  makeFilter();
}

function draw() {
  randomSeed(seed);
  drawDynamicBackground();

  push();
  translate(width/2, height/2);

  organisms.forEach(org => {
    org.update();
    org.display();
  });

  drawBubbles();
  pop();

  image(overAllTexture, 0, 0);
}

function drawDynamicBackground() {
  let yOffset = sin(frameCount*0.02)*50;
  for(let y=0; y<height; y++){
    let inter = map(y+yOffset, 0, height, 0, 1);
    let c = lerpColor(color(colorbg[0]), color(colorbg2[0]), inter);
    stroke(c);
    line(0, y, width, y);
  }
}

function drawBubbles() {
  if(random() < 0.1) {
    bubbles.push({
      x: random(-width/2, width/2),
      y: height/2,
      size: random(3,8),
      speed: random(1,3),
      life: 255
    });
  }

  bubbles.forEach((b, index) => {
    b.y -= b.speed;
    b.life -= 2;
    fill(200, 50, 100, b.life);
    noStroke();
    ellipse(b.x, b.y, b.size);

    if(b.life <= 0) {
      bubbles.splice(index, 1);
    }
  });
}

function makeFilter() {
  overAllTexture = createGraphics(width, height);
  overAllTexture.background(255);
  overAllTexture.fill(255, 2);
  for(let i=0; i<500; i++){
    overAllTexture.ellipse(
      random(width), random(height),
      random(50,100), random(50,100)
    );
  }
  overAllTexture.filter(BLUR, 3);
}

function mouseMoved() {
  organisms.forEach(org => {
    let d = dist(
      mouseX, mouseY, 
      org.x + width/2, 
      org.y + height/2
    );
    if(d < 100) {
      let angle = atan2(
        org.y + height/2 - mouseY, 
        org.x + width/2 - mouseX
      );
      org.speedX = cos(angle)*0.5;
      org.speedY = sin(angle)*0.5;
    }
  });
}

function windowResized() {
  resizeCanvas(windowWidth, windowHeight);
  makeFilter();
}

