let seed = Math.random() * 15283;
let t;
let num;
let radius, mySize, margin;
let sizes = [];
let v_planet = [];

// sparkles on background
let sparkles = [];
const sparkleCount = 150;

// color palette
const pastel  = ["#58508D","#C1E1C1","#C1D4E1","#E1C1E1","#E1E1C1"];
const bright  = ["#FF6363","#FFA600","#BC5090","#FFD1DC","#003F5C"];
const vintage = ["#D08770","#A3BE8C","#EBCB8B","#B48EAD","#81A1C1"];
const light   = ["#FFFF00","#FFD740","#FFAB40","#FF6E40","#FF8A80",
                 "#EA80FC","#B388FF","#8C9EFF","#FFD180","#84FFFF"];
const neon    = ["#FF6EC7","#39FF14","#0FF0FC","#FF3131","#FFFF66"];
const ocean   = ["#006494","#247BA0","#1B98E0","#E8F1F2","#0E7C7B"];
const retro   = ["#D72638","#3F88C5","#F49D37","#140F2D","#F2E8CF"];
const sunset  = ["#FF9E9D","#FEC260","#F28C28","#D1495B","#69306D"];

// localStorage loop
const paletteList = [pastel, bright, vintage, light, neon, ocean, retro, sunset];
let paletteIdx;
let palette;

let color_bg;

function setup() {
  randomSeed(seed);

  // 轮询选调色盘
  paletteIdx = parseInt(localStorage.getItem('paletteIdx')) || 0;
  palette    = paletteList[paletteIdx];
  localStorage.setItem('paletteIdx', (paletteIdx + 1) % paletteList.length);

  mySize = min(windowWidth, windowHeight);
  margin = mySize / 100;
  createCanvas(mySize, mySize, WEBGL);

  color_bg = "#202020";
  background(color_bg);

  num    = int(random(10, 30));
  radius = mySize * 0.75;
  for (let a = 0; a < TAU; a += TAU / num) {
    sizes.push(random(0.1, 0.5));
  }

  initSparkles();
  t = 0;
}

function initSparkles() {
  for (let i = 0; i < sparkleCount; i++) {
    let theta = random(TAU);
    let phi   = acos(random(-1, 1));
    let r     = random(radius * 0.8, radius * 1.5);
    let x = r * sin(phi) * cos(theta);
    let y = r * sin(phi) * sin(theta);
    let z = r * cos(phi);
    sparkles.push({ pos: createVector(x, y, z), size: random(1, 4), color: random(palette) });
  }
}

function draw() {
  background(color_bg);

  // 计算 3D 环状路径点
  for (let i = 0; i < num; i++) {
    let a = (TAU / num) * i;
    let x = radius * sin(a + t) / random(5, 3);
    let y = radius * cos(a + t) / random(3, 5);
    v_planet[i] = createVector(x, y, 0);
  }

  let colorIdx = 0;
  push();
  for (let q = 0; q < 1/5; q += 2 * random(0.01, 0.02)) {
    rotateX(random(TAU) + sin(-t)/5 + q);
    rotateY(random(TAU) + cos(t)/5 + q);
    rotateZ(random(TAU) + sin(-t)/5 + q);

    for (let i = 0; i < num; i++) {
      // middle毛线球球
      push();
      let d      = sin(2*t + i) * random(radius/2, radius/4);
      let x_plus = 0.5 * random(-d, d);
      let y_plus = 0.5 * random(-d, d);
      let z_plus = 0.5 * random(-d, d);
      translate(v_planet[i].x + x_plus, v_planet[i].y + y_plus, z_plus);
      rotateX(random(TAU) + t);
      rotateY(random(-TAU) + t);
      rotateZ(random(PI) + t);
      noStroke();
      fill(palette[colorIdx % palette.length]);
      colorIdx++;
      sphere(random(2,8));
      pop();

      // 曲线
      noFill();
      strokeWeight(random(2.5));
      stroke(palette[colorIdx % palette.length]);
      colorIdx++;
      beginShape();
      curveVertex(0,0,0); curveVertex(0,0,0);
      let x1 = v_planet[i].x + (1+sin(t))*x_plus/4;
      let y1 = v_planet[i].y + (1+sin(t))*y_plus/4;
      let z1 = (1+sin(t))*z_plus/4;
      let x2 = v_planet[i].x - (1+sin(t))*x_plus/4*3;
      let y2 = v_planet[i].y - (1+sin(t))*y_plus/4*3;
      let z2 = (1+sin(t))*z_plus/4*3;
      let x3 = v_planet[i].x + (1+sin(t))*x_plus;
      let y3 = v_planet[i].y + (1+sin(t))*y_plus;
      let z3 = (1+sin(t))*z_plus;
      curveVertex(x1,y1,z1);
      curveVertex(x2,y2,z2);
      curveVertex(x3,y3,z3);
      curveVertex(x3,y3,z3);
      endShape();

      // 毛线特效
      let p0 = createVector(0,0,0);
      let p1 = createVector(x1,y1,z1);
      let p2 = createVector(x2,y2,z2);
      let p3 = createVector(x3,y3,z3);
      drawFuzzySegment3D(p0,p1,colorIdx);
      drawFuzzySegment3D(p1,p2,colorIdx);
      drawFuzzySegment3D(p2,p3,colorIdx);

      // 额外副本
      stroke(palette[(colorIdx+2)%palette.length]);
      strokeWeight(1);
      beginShape();
      curveVertex(0,0,0); curveVertex(0,0,0);
      curveVertex(x1*1.02,y1*1.02,z1*1.02);
      curveVertex(x2*0.98,y2*0.98,z2*0.98);
      curveVertex(x3*1.04,y3*1.04,z3*1.04);
      curveVertex(x3*1.04,y3*1.04,z3*1.04);
      endShape();
    }
  }
  pop();

  // 绘制小光点，闪烁同步主题频率
  drawSparkles();

  t += 0.005;
}

function drawSparkles() {
  push(); noStroke();
  rotateX(sin(t/2)*0.2);
  rotateY(cos(t/3)*0.3);
  rotateZ(sin(t/4)*0.1);

  // 全局闪烁因子，与主题一致
  let blink = (sin(t*5) + 1)/2;  // 0-1

  for (let s of sparkles) {
    let alpha = map(blink, 0,1,50,255);
    fill(color(red(s.color), green(s.color), blue(s.color), alpha));
    push(); translate(s.pos.x, s.pos.y, s.pos.z);
    // 大小也随闪烁
    let size = s.size * (0.5 + blink);
    sphere(size);
    pop();
  }
  pop();
}

function drawFuzzySegment3D(v1, v2, ciStart) {
  const steps = 40, maxOff = 20;
  for (let k=0; k<steps; k++){
    let tt = k/(steps-1);
    let pt = p5.Vector.lerp(v1,v2,tt);
    let off = p5.Vector.random3D().mult(random(0,maxOff));
    let ci = (ciStart + k) % palette.length;
    stroke(palette[ci]);
    strokeWeight(random(0.2,1.2));
    line(pt.x,pt.y,pt.z,pt.x+off.x,pt.y+off.y,pt.z+off.z);
  }
}

