// The circle is drawn when the user presses down the mouse, and the circle is fixed and stored when the mouse is released. If an overlap occurs or the new circle goes beyond the boundary of the canvas, the circle will disappear
//credit1: Asked ChatGPT how to measure the distance between two objects, and it taught me dist()
//credit2: GPT sugeested me to use const() instead of let(), whitch is more stable?

let circleFilling = false;
let circleSize = 0;
let circleColor;

const circles = [];

function setup() {
  createCanvas(500, 500);
  circleColor = color(random(255), random(255), random(255));
  strokeWeight(0);
}

function draw() {
  background(100, 30, 10);

  if (circleFilling) {
    circleSize += 2; //circle Size gets larger by 2 per frame

    // Determine if there are overlapping circles
    let overlapping = false;
    for (const c of circles) {
      if (dist(c.x, c.y, mouseX, mouseY) < circleSize / 2 + c.size / 2 + 2) {
        overlapping = true;
        break;
      }
    }

    // If there is an overlap or if it goes beyond the canvas, stop drawing
    if (overlapping || isOffScreen()) {
      circleFilling = false;
    }

    fill(circleColor);
    circle(mouseX, mouseY, circleSize);
  }

  for (let i = 0; i < circles.length; i++) {
    fill(circles[i].color);
    circle(circles[i].x, circles[i].y, circles[i].size);
  }
}

function isOffScreen() {
  return (
    mouseX < circleSize / 2 ||
    mouseX > width - circleSize / 2 ||
    mouseY < circleSize / 2 ||
    mouseY > height - circleSize / 2
  );
}

function mousePressed() {
  circleSize = 0;
  circleColor = color(random(255), random(255), random(255));
  circleFilling = true;
}

function mouseReleased() {
  if (circleFilling) {
    circles.push({
      x: mouseX,
      y: mouseY,
      size: circleSize,
      color: circleColor,
    });
  }
  circleFilling = false;
}

