let yarns = [];
let wovenGrid;
const canvasWidth = 600;
const canvasHeight = 600;
const yarnColors = [
  '#FF5252', '#FF4081', '#E040FB', '#7C4DFF', 
  '#536DFE', '#448AFF', '#40C4FF', '#18FFFF',
  '#64FFDA', '#69F0AE', '#B2FF59', '#EEFF41',
  '#FFFF00', '#FFD740', '#FFAB40', '#FF6E40',
  '#FF8A80', '#EA80FC', '#B388FF', '#8C9EFF',
  '#FFD180', '#84FFFF'
];

// Yarn class with added fuzzy effect
class Yarn {
  constructor(startX, startY, length, thickness, color) {
    this.points = [];
    this.thickness = thickness || random(8, 16);
    this.color = color || random(yarnColors);
    this.dragging = false;
    this.dragIndex = -1;
    this.dragOffset = createVector(0, 0);
    this.elasticity = random(0.03, 0.08); // elasticity coefficient
    this.tension = random(0.5, 0.8);      // tension coefficient
    this.gravity = random(0.05, 0.2);     // gravity effect
    this.fuzzyDensity = random(8, 12);    // number of fuzzy lines per segment
    this.fuzzyLength = random(5, 15);     // length of fuzzy lines

    let x = startX;
    let y = startY;
    const segmentLength = length / 20; // divide into 20 segments

    for (let i = 0; i < 20; i++) {
      let nextX = x + random(-10, 10);
      let nextY = y + random(-5, 15);

      this.points.push({
        x: nextX,
        y: nextY,
        origX: nextX, // original position for spring-back
        origY: nextY,
        vx: 0,        // velocity
        vy: 0
      });

      x = nextX;
      y = nextY;
    }
  }

  // update yarn physics
  update() {
    for (let i = 0; i < this.points.length; i++) {
      let p = this.points[i];

      // skip dragged point
      if (!this.dragging || i !== this.dragIndex) {
        // spring force toward original position
        let dx = p.origX - p.x;
        let dy = p.origY - p.y;
        p.vx += dx * this.elasticity;
        p.vy += dy * this.elasticity;

        // apply gravity
        p.vy += this.gravity;

        // tension with previous point
        if (i > 0) {
          let prev = this.points[i - 1];
          dx = prev.x - p.x;
          dy = prev.y - p.y;
          let dist = sqrt(dx * dx + dy * dy);
          let targetDist = 15;

          if (dist > targetDist) {
            let factor = this.tension * (dist - targetDist) / dist;
            p.vx += dx * factor;
            p.vy += dy * factor;
            prev.vx -= dx * factor;
            prev.vy -= dy * factor;
          }
        }

        // tension with next point
        if (i < this.points.length - 1) {
          let next = this.points[i + 1];
          dx = next.x - p.x;
          dy = next.y - p.y;
          let dist = sqrt(dx * dx + dy * dy);
          let targetDist = 15;

          if (dist > targetDist) {
            let factor = this.tension * (dist - targetDist) / dist;
            p.vx += dx * factor;
            p.vy += dy * factor;
            next.vx -= dx * factor;
            next.vy -= dy * factor;
          }
        }

        // damping
        p.vx *= 0.95;
        p.vy *= 0.95;

        // update position
        p.x += p.vx;
        p.y += p.vy;
      }
    }
  }

  // Draw fuzzy lines radiating from a point
  drawFuzzyEffect(x, y, size) {
    let baseColor = color(this.color);
    let fuzzyColor1 = color(red(baseColor), green(baseColor), blue(baseColor), 80); // semi-transparent
    let fuzzyColor2 = color(red(baseColor), green(baseColor), blue(baseColor), 20); // more transparent

    for (let i = 0; i < this.fuzzyDensity; i++) {
      let angle = random(TWO_PI);
      let fuzzyLength = this.fuzzyLength * (0.7 + 0.6 * random());
      let endX = x + fuzzyLength * cos(angle);
      let endY = y + fuzzyLength * sin(angle);

      // Draw gradient line for fuzzy effect
      this.gradientLine(x, y, endX, endY, fuzzyColor1, fuzzyColor2);
    }
  }

  // Create a gradient line
  gradientLine(x1, y1, x2, y2, color1, color2) {
    let grad = drawingContext.createLinearGradient(x1, y1, x2, y2);
    grad.addColorStop(0, color1);
    grad.addColorStop(1, color2);
    drawingContext.strokeStyle = grad;
    drawingContext.lineWidth = random(0.5, 1.5);

    line(x1, y1, x2, y2);
  }

  // render yarn with fuzzy effect
  display() {
    // Draw the base yarn
    noFill();
    strokeWeight(this.thickness);
    stroke(this.color);

    beginShape();
    for (let i = 0; i < this.points.length; i++) {
      let p = this.points[i];
      vertex(p.x, p.y);
    }
    endShape();

    // Add fuzzy effects along the yarn
    strokeWeight(1);
    for (let i = 0; i < this.points.length - 1; i++) {
      let p1 = this.points[i];
      let p2 = this.points[i + 1];

      // Calculate distance between points
      let d = dist(p1.x, p1.y, p2.x, p2.y);
      let steps = max(1, floor(d / 5)); // Add fuzzy points every 5 pixels

      // Add fuzzy effects along the segment
      for (let j = 0; j <= steps; j++) {
        let t = j / steps;
        let x = lerp(p1.x, p1.y, p2.x, p2.y, t);
        let y = lerp(p1.y, p1.y, p2.y, p2.y, t);

        // Add some randomness to fuzzy point positions
        x += random(-2, 2);
        y += random(-2, 2);

        this.drawFuzzyEffect(x, y, this.thickness);
      }
    }

    // Draw ends
    fill(this.color);
    noStroke();
    ellipse(this.points[0].x, this.points[0].y, this.thickness * 1.2, this.thickness * 1.2);
    ellipse(this.points[this.points.length - 1].x, this.points[this.points.length - 1].y, this.thickness * 1.2, this.thickness * 1.2);

    // Thicker points at some intersections with fuzzy effect
    for (let i = 3; i < this.points.length - 3; i += 4) {
      let p = this.points[i];
      fill(this.color);
      noStroke();
      ellipse(p.x, p.y, this.thickness * 1.5, this.thickness * 1.5);
      this.drawFuzzyEffect(p.x, p.y, this.thickness * 1.5);
    }
  }

  // Helper function for lerp on both x and y
  lerp(x1, y1, x2, y2, t) {
    return {
      x: x1 + (x2 - x1) * t,
      y: y1 + (y2 - y1) * t
    };
  }

  // check if mouse is over a point
  checkDrag(mouseX, mouseY) {
    for (let i = 0; i < this.points.length; i++) {
      let p = this.points[i];
      let d = dist(mouseX, mouseY, p.x, p.y);
      if (d < this.thickness * 1.5) {
        this.dragging = true;
        this.dragIndex = i;
        this.dragOffset.x = p.x - mouseX;
        this.dragOffset.y = p.y - mouseY;
        return true;
      }
    }
    return false;
  }

  // update position while dragging
  drag(mouseX, mouseY) {
    if (this.dragging && this.dragIndex >= 0) {
      let p = this.points[this.dragIndex];
      p.x = mouseX + this.dragOffset.x;
      p.y = mouseY + this.dragOffset.y;

      // adjust nearby points for continuity
      const influence = 3;
      for (let i = 1; i <= influence; i++) {
        // previous points
        if (this.dragIndex - i >= 0) {
          let factor = (influence - i + 1) / (influence + 1);
          let prev = this.points[this.dragIndex - i];
          prev.x += (p.x - prev.x) * factor * 0.3;
          prev.y += (p.y - prev.y) * factor * 0.3;
        }
        // next points
        if (this.dragIndex + i < this.points.length) {
          let factor = (influence - i + 1) / (influence + 1);
          let next = this.points[this.dragIndex + i];
          next.x += (p.x - next.x) * factor * 0.3;
          next.y += (p.y - next.y) * factor * 0.3;
        }
      }
    }
  }

  // stop dragging
  endDrag() {
    this.dragging = false;
    this.dragIndex = -1;
  }
}

// class to create and manage multiple yarns
class WovenGrid {
  constructor() {
    this.yarns = [];
    this.draggingYarn = null;

    // create horizontal yarns
    for (let y = 100; y < 450; y += 30) {
      let extraLength = random() > 0.7 ? random(50, 120) : 0;
      this.createHorizontalYarn(50, y, 400 + extraLength, random(yarnColors));
    }

    // create vertical yarns
    for (let x = 100; x < 450; x += 30) {
      let extraLength = random() > 0.7 ? random(50, 100) : 0;
      this.createVerticalYarn(x, 50, 400 + extraLength, random(yarnColors));
    }

    // add decorative diagonal yarns
    for (let i = 0; i < 8; i++) {
      let startX = random(50, 450);
      let startY = random(50, 450);
      let angle = random(TWO_PI);
      let length = random(100, 250);
      let endX = startX + cos(angle) * length;
      let endY = startY + sin(angle) * length;
      this.createCustomYarn(startX, startY, endX, endY, random(yarnColors));
    }

    // extend some horizontal yarns with dangling ends
    let danglingCount = 5;
    let selectedYarns = [];
    let horizontalYarns = this.yarns.filter(yarn => Math.abs(yarn.points[0].y - yarn.points[yarn.points.length - 1].y) < 50);

    for (let i = 0; i < danglingCount && horizontalYarns.length > 0; i++) {
      let randomIndex = floor(random(horizontalYarns.length));
      selectedYarns.push(horizontalYarns[randomIndex]);
      horizontalYarns.splice(randomIndex, 1);
    }

    for (let yarn of selectedYarns) {
      let lastPoint = yarn.points[yarn.points.length - 1];
      let extraLength = random(100, 180);
      let extraPoints = 10;

      for (let i = 1; i <= extraPoints; i++) {
        let progress = i / extraPoints;
        let curve = sin(progress * PI) * 20;
        let newPoint = {
          x: lastPoint.x + curve + random(-10, 10),
          y: lastPoint.y + progress * extraLength,
          origX: lastPoint.x + curve + random(-10, 10),
          origY: lastPoint.y + progress * extraLength,
          vx: 0,
          vy: 0
        };
        yarn.points.push(newPoint);
      }

      yarn.gravity = random(0.2, 0.4);
    }
  }

  createHorizontalYarn(x, y, length, color) {
    let yarn = new Yarn(x, y, length, random(10, 15), color);
    for (let i = 0; i < yarn.points.length; i++) {
      let progress = i / (yarn.points.length - 1);
      let waveY = sin(progress * TWO_PI * random(1, 3)) * random(5, 15);
      yarn.points[i].x = x + progress * length + random(-5, 5);
      yarn.points[i].y = y + waveY + random(-8, 8);
      yarn.points[i].origX = yarn.points[i].x;
      yarn.points[i].origY = yarn.points[i].y;
    }
    this.yarns.push(yarn);
  }

  createVerticalYarn(x, y, length, color) {
    let yarn = new Yarn(x, y, length, random(10, 15), color);
    for (let i = 0; i < yarn.points.length; i++) {
      let progress = i / (yarn.points.length - 1);
      let waveX = sin(progress * TWO_PI * random(1, 3)) * random(5, 15);
      yarn.points[i].x = x + waveX + random(-8, 8);
      yarn.points[i].y = y + progress * length + random(-5, 5);
      yarn.points[i].origX = yarn.points[i].x;
      yarn.points[i].origY = yarn.points[i].y;
    }
    this.yarns.push(yarn);
  }

  createCustomYarn(startX, startY, endX, endY, color) {
