      this.draggingYarn.endDrag();
      this.draggingYarn = null;
    }

    for (let i = 0; i < this.yarns.length; i++) {
      this.yarns[i].update();
    }
  }

  display() {
    // Draw yarns in order (to create layering effect)
    for (let i = 0; i < this.yarns.length; i++) {
      this.yarns[i].display();
    }
  }
