// Yarn with spring-back physics
class Yarn {
  constructor(startX, startY, length, color) {
    this.points = [];
    this.thickness = random(8,16);
    this.color = color;
    // slower subtle motion
    this.elasticity = random(0.02,0.05);
    this.tension    = random(0.4,0.6);
    this.gravity    = random(0.03,0.1);
    // initial chain
    let x=startX, y=startY;
    let seg = length/20;
    for (let i=0; i<20; i++) {
      let nx = x + random(-5,5);
      let ny = y + random(-3,8);
      this.points.push({ x:nx, y:ny, origX:nx, origY:ny, vx:0, vy:0 });
      x=nx; y=ny;
    }
  }

  update() {
    this.points.forEach((p,i)=>{
      let dx = p.origX - p.x;
      let dy = p.origY - p.y;
      p.vx += dx * this.elasticity;
      p.vy += dy * this.elasticity + this.gravity;
      satisfyTension(i, this.points, this.tension);
      p.vx *= 0.92;
      p.vy *= 0.92;
      p.x += p.vx;
      p.y += p.vy;
    });
  }

  display() {
    stroke(this.color);
    strokeWeight(this.thickness);
    noFill();
    beginShape();
    this.points.forEach(p=>vertex(p.x,p.y));
    endShape();
  }

  applyFingerInteraction(preds) {
    const tips=[4,8,12,16,20];
    const inf = 50;
    const str = 0.2;
    preds.forEach(hand=>{
      tips.forEach(i=>{
        let [fx,fy] = hand.landmarks[i];
        this.points.forEach(p=>{
          let d = dist(p.x,p.y,fx,fy);
          if (d < inf) {
            p.x += (fx-p.x)*str;
            p.y += (fy-p.y)*str;
          }
        });
      });
    });
  }
}

function satisfyTension(idx, pts, tens) {
  let p = pts[idx];
  [-1,1].forEach(dir=>{
    let j = idx+dir;
    if (j>=0 && j<pts.length) {
      let q=pts[j];
      let dx=q.x-p.x, dy=q.y-p.y;
      let d = sqrt(dx*dx + dy*dy);
      let tgt=15;
      if (d>tgt) {
        let f = tens*(d-tgt)/d;
        p.vx += dx*f;
        p.vy += dy*f;
        q.vx -= dx*f;
        q.vy -= dy*f;
      }
    }
  });
}

// Woven grid preserving original geometry
class WovenGrid {
  constructor() {
    this.yarns = [];
    // horizontal yarns from left off-screen
    for (let y=100; y<450; y+=30) {
      this.createHorizontal(-100,y,canvasWidth+200, random(yarnColors));
