    // vertical yarns from top off-screen
    for (let x=100; x<450; x+=30) {
      this.createVertical(x,-100,canvasHeight+200, random(yarnColors));
    }
    // diagonal yarns from random edges
    for (let i=0;i<8;i++){
      let edge = random(['top','left']);
      let sx = edge==='top'? random(0,canvasWidth):-100;
      let sy = edge==='top'? -100: random(0,canvasHeight);
      let ex = random(canvasWidth+50);
      let ey = random(canvasHeight+50);
      this.createDiagonal(sx,sy,ex,ey, random(yarnColors));
    }
  }

  createHorizontal(x,y,len,color) {
    let yrn = new Yarn(x,y,len,color);
    yrn.points.forEach((pt,i)=>{
      let t=i/(yrn.points.length-1);
      let px = x + t*len + random(-5,5);
      let py = y + sin(t*PI*2*random(1,3))*random(5,15) + random(-8,8);
      pt.x=pt.origX=px; pt.y=pt.origY=py;
    });
    this.yarns.push(yrn);
  }

  createVertical(x,y,len,color) {
    let yrn = new Yarn(x,y,len,color);
    yrn.points.forEach((pt,i)=>{
      let t=i/(yrn.points.length-1);
      let px = x + sin(t*PI*2*random(1,3))*random(5,15) + random(-8,8);
      let py = y + t*len + random(-5,5);
      pt.x=pt.origX=px; pt.y=pt.origY=py;
    });
    this.yarns.push(yrn);
  }

  createDiagonal(sx,sy,ex,ey,color) {
    let len = dist(sx,sy,ex,ey);
    let yrn = new Yarn(sx,sy,len,color);
    yrn.points.forEach((pt,i)=>{
      let t=i/(yrn.points.length-1);
      let px = lerp(sx,ex,t) + random(-10,10);
      let py = lerp(sy,ey,t) + random(-10,10);
      pt.x=pt.origX=px; pt.y=pt.origY=py;
    });
    this.yarns.push(yrn);
  }

  update() {
    this.yarns.forEach(y=>y.update());
  }

  applyFingerInteraction(preds) {
    this.yarns.forEach(y=>y.applyFingerInteraction(preds));
  }

  display() {
    this.yarns.forEach(y=>y.display());
  }
}

