// ElasticThread class: chain of points with spring-back and hand influence
class ElasticThread {
  constructor(n, color, offset) {
    this.n = n;
    this.color = color;
    this.offset = offset;
    this.points = [];
    this.v = [];
    this.k = 0.1;    // spring constant
    this.damp = 0.9; // damping
    for(let i=0;i<n;i++){
      this.points.push(createVector(0,0,0));
      this.v.push(createVector(0,0,0));
    }
  }

  update(handPts) {
    // base motion for segment 0
    let base = this.points[0];
    base.set(0,0,0);
    // subsequent segments
    for(let i=1;i<this.n;i++){
      let prev = this.points[i-1];
      let cur = this.points[i];
      // desired oscillation
      let dx = sin(frameCount/this.offset + i)*20;
      let dy = cos(frameCount/this.offset + i)*20;
      let target = p5.Vector.add(prev, createVector(dx,dy,0));
      // spring force
      let force = p5.Vector.sub(target,cur).mult(this.k);
      this.v[i].add(force);
      // hand influence
      handPts.forEach(p=>{
        let d = p5.Vector.dist(cur,p);
        if(d<100) this.v[i].add(p5.Vector.sub(p,cur).mult(0.02));
      });
      // damping & update
      this.v[i].mult(this.damp);
      cur.add(this.v[i]);
    }
  }

  display() {
    noFill(); stroke(this.color); strokeWeight(4);
    beginShape();
    this.points.forEach(p=>vertex(p.x,p.y,p.z));
    endShape();
  }
}

