// Verlet Particle
class Particle {
  constructor(x, y, locked = false) {
    this.pos = createVector(x, y);
    this.prevPos = this.pos.copy();
    this.acc = createVector();
    this.locked = locked;
    this.restPos = this.pos.copy();
  }
  addForce(f) {
    this.acc.add(f);
  }
  verlet() {
    if (this.locked) return;
    let vel = p5.Vector.sub(this.pos, this.prevPos).mult(0.99);
    this.prevPos.set(this.pos);
    this.pos.add(vel).add(this.acc);
    this.acc.set(0, 0);
  }
}

// Spring Constraint
class Spring {
  constructor(a, b, restLen, stiffness) {
    this.a = a;
    this.b = b;
    this.restLen = restLen;
    this.stiffness = stiffness;
  }
  satisfy() {
    let delta = p5.Vector.sub(this.b.pos, this.a.pos);
    let d = delta.mag();
    let diff = (d - this.restLen) / d;
    let off = delta.mult(0.5 * this.stiffness * diff);
    if (!this.a.locked) this.a.pos.add(off);
    if (!this.b.locked) this.b.pos.sub(off);
  }
}

// Yarn as Chain of Particles + Springs
class Yarn {
  constructor(x, y, length) {
    this.thickness = random(8, 16);
    this.color = random(palette);
    this.particles = [];
    this.springs = [];
    this._init(x, y, length);
  }
  _init(x, y, length) {
    const segs = 15;
    const segLen = length / segs;
    for (let i = 0; i <= segs; i++) {
      let px = x + (length * i / segs) + random(-3, 3);
      let py = y + random(-3, 3);
      let p = new Particle(px, py, i === 0);
      this.particles.push(p);
      if (i > 0) {
        let a = this.particles[i - 1];
        this.springs.push(new Spring(a, p, segLen, 0.8));
        if (i > 1) {
          let b = this.particles[i - 2];
          this.springs.push(new Spring(b, p, segLen * 2, 0.2));
        }
      }
    }
  }
  applyForces(predictions) {
    // Wind force
    let wind = createVector(sin(frameCount * 0.02) * 0.2, 0.1);
    this.particles.forEach(p => {
      p.addForce(wind);
      // Elastic return force
      let dir = p5.Vector.sub(p.restPos, p.pos).mult(0.02);
      p.addForce(dir);
    });
    // Finger interaction force
    const influence = 60;
    const strength = 0.5;
    predictions.forEach(hand => {
      [4, 8, 12, 16, 20].forEach(i => {
        const [fx, fy] = hand.landmarks[i];
        this.particles.forEach(p => {
          let d = dist(p.pos.x, p.pos.y, fx, fy);
          if (d < influence) {
            let force = createVector(fx - p.pos.x, fy - p.pos.y)
                          .setMag(map(d, 0, influence, strength, 0));
            p.addForce(force);
          }
        });
      });
    });
  }
  update(predictions) {
    this.applyForces(predictions);
    this.particles.forEach(p => p.verlet());
    for (let i = 0; i < 4; i++) this.springs.forEach(s => s.satisfy());
  }
  display() {
    // Collect points for brush
    const pts = this.particles.map(p => [p.pos.x, p.pos.y]);
    brush.set('HB', this.color, this.thickness);
    brush.spline(pts, 0.6);
  }
}

// WovenGrid: organizes horizontal, vertical, diagonal yarns
class WovenGrid {
  constructor() {
    this.yarns = [];
    // Horizontal lines
    for (let y = 100; y <= 450; y += 30) {
      this.yarns.push(new Yarn(50, y, 500));
    }
    // Vertical lines (rotated)
    for (let x = 100; x <= 450; x += 30) {
      let w = new Yarn(x, 50, 500);
      w.particles.forEach(p => {
        let dx = p.pos.x - x;
        let dy = p.pos.y - 50;
        p.pos.set(x + dy, 50 + dx);
        p.prevPos.set(p.pos);
        p.restPos.set(p.pos);
      });
      this.yarns.push(w);
    }
    // Diagonal decorative lines
    for (let i = 0; i < 6; i++) {
      let sx = random(50, 450);
      let sy = random(50, 450);
      let ang = random(TWO_PI);
      let len = random(200, 300);
      let ex = sx + cos(ang) * len;
      let ey = sy + sin(ang) * len;
      let w = new Yarn(sx, sy, len);
      w.particles.forEach((p, idx) => {
        let t = idx / (w.particles.length - 1);
        let tx = lerp(sx, ex, t);
        let ty = lerp(sy, ey, t);
        p.pos.set(tx + random(-8, 8), ty + random(-8, 8));
        p.prevPos.set(p.pos);
        p.restPos.set(p.pos);
      });
      this.yarns.push(w);
    }
  }
  update(predictions) {
    this.yarns.forEach(y => y.update(predictions));
  }
  display() {
    this.yarns.forEach(y => y.display());
  }
}

