class Particle {
  constructor(x, y, locked = false) {
    this.pos = createVector(x, y);
    this.prevPos = createVector(x, y);
    this.acc = createVector(0, 0);
    this.locked = locked;
    this.fuzzyEffect = random(0.8, 1.2);
  }
  addForce(f) { this.acc.add(f); }
  verlet() {
    if (this.locked) return;
    let vel = p5.Vector.sub(this.pos, this.prevPos);
    this.prevPos.set(this.pos);
    this.pos.add(vel).add(this.acc);
    this.acc.set(0, 0);
  }
}

class Spring {
  constructor(a, b, restLen, stiffness) {
    this.a = a; this.b = b; this.restLen = restLen; this.stiffness = stiffness;
  }
  satisfy() {
    let delta = p5.Vector.sub(this.b.pos, this.a.pos);
    let dist = delta.mag();
    let diff = (dist - this.restLen) / dist;
    let offset = delta.mult(0.5 * this.stiffness * diff);
    if (!this.a.locked) this.a.pos.add(offset);
    if (!this.b.locked) this.b.pos.sub(offset);
  }
}

class Yarn {
  constructor(x, y, length, thickness, color) {
    this.thickness = thickness * 1.5;
    this.color = color;
    this.colorObj = this.parseColor(color);
    this.particles = [];
    this.springs = [];
    this.init(x, y, length);
    this.fuzzySize = random(35, 50);
    this.fuzzyDensity = int(random(30, 40));
  }
  parseColor(hex) {
    const r = parseInt(hex.slice(1,3),16);
    const g = parseInt(hex.slice(3,5),16);
    const b = parseInt(hex.slice(5,7),16);
    return { r, g, b };
  }
  init(x, y, length) {
    let segs = 20, segLen = length/segs;
    for (let i=0; i<=segs; i++) {
      let px = x + length*(i/segs), py = y;
      let p = new Particle(px+random(-5,5), py+random(-5,5), i===0);
      this.particles.push(p);
      if (i>0) {
        let a = this.particles[i-1];
        this.springs.push(new Spring(a, p, segLen, 0.8));
        if (i>1) this.springs.push(new Spring(this.particles[i-2], p, segLen*2, 0.2));
      }
    }
  }
  applyWind() { this.particles.forEach(p=>p.addForce(createVector(sin(frameCount*0.02)*windStrength,0.1))); }
  applyFingerInteraction(preds) {
    preds.forEach(hand => [4,8,12,16,20].forEach(i => {
      let [fx,fy] = hand.landmarks[i];
      this.particles.forEach(p=>{
        let d = dist(p.pos.x,p.pos.y,fx,fy);
        if (d<50) p.pos.add(p5.Vector.sub(createVector(fx,fy),p.pos).mult(0.3));
      });
    }));
  }
  update() {
    this.particles.forEach(p=>p.verlet());
    for (let i=0;i<5;i++) this.springs.forEach(s=>s.satisfy());
  }
  display() {
    // 主干
    noFill(); strokeWeight(this.thickness); stroke(this.color);
    beginShape(); this.particles.forEach(p=>vertex(p.pos.x,p.pos.y)); endShape();
    // 毛茸茸
    this.particles.slice(0,-1).forEach((p,i)=>{
      let q=this.particles[i+1];
      let d=p5.Vector.dist(p.pos,q.pos), steps=constrain(int(d/8),2,12);
      for(let j=0;j<=steps;j++){
        let t=j/steps;
        let fp=createVector(lerp(p.pos.x,q.pos.x,t),lerp(p.pos.y,q.pos.y,t));
        fp.add(random(-2,2),random(-2,2));
        let sf=this.particles[i].fuzzyEffect*map(sin(frameCount*0.05+i*0.5),-1,1,0.9,1.3);
        let c1=`rgba(${this.colorObj.r},${this.colorObj.g},${this.colorObj.b},0.8)`;
        let c2=`rgba(${this.colorObj.r},${this.colorObj.g},${this.colorObj.b},0.2)`;
        drawRadiatingLines(fp,this.fuzzyDensity,1.2,this.fuzzySize*sf,c1,c2);
      }
    });
  }
}

class WovenGrid {
  constructor() {
    this.yarns=[];
    for(let y=100;y<=450;y+=60)this.yarns.push(new Yarn(50,y,500,random(8,12),random(yarnColors)));
    for(let x=100;x<=450;x+=60){
      let y=new Yarn(x,50,500,random(8,12),random(yarnColors));
      y.particles.forEach(p=>{let dx=p.pos.x-x,dy=p.pos.y-50;p.pos.set(x+dy,50+dx);p.prevPos.set(p.pos);});
      this.yarns.push(y);
    }
    for(let i=0;i<4;i++){
      let sx=random(50,450),sy=random(50,450),ang=random(TWO_PI);
      let len=random(200,300),ex=sx+cos(ang)*len,ey=sy+sin(ang)*len;
      let y=new Yarn(sx,sy,len,random(6,10),random(yarnColors));
      y.particles.forEach((p,j)=>{let t=j/(y.particles.length-1);p.pos.set(lerp(sx,ex,t)+random(-10,10),lerp(sy,ey,t)+random(-10,10));p.prevPos.set(p.pos);});
      this.yarns.push(y);
    }
  }
  applyWind() { this.yarns.forEach(y=>y.applyWind()); }
  applyFingerInteraction(preds) { this.yarns.forEach(y=>y.applyFingerInteraction(preds)); }
  update() { this.yarns.forEach(y=>y.update()); }
  display() { this.yarns.forEach(y=>y.display()); }
}

function drawRadiatingLines(pt,d,w,s,c1,c2){
  strokeWeight(d*0+ w);
  for(let i=0;i<d;i++){let r=s*(0.7+0.3*random()),a=random(TWO_PI);
    let ex=pt.x+r*cos(a),ey=pt.y+r*sin(a);
    gradientLine(pt.x,pt.y,ex,ey,c1,c2);
    if(random()>0.7){let bp=createVector(lerp(pt.x,ex,random(0.3,0.7)),lerp(pt.y,ey,random(0.3,0.7)));
      let ba=a+random(-PI/4,PI/4),bl=r*random(0.3,0.5),bx=bp.x+bl*cos(ba),by=bp.y+bl*sin(ba);
      gradientLine(bp.x,bp.y,bx,by,c1,c2);
    }
  }
}

function gradientLine(x1,y1,x2,y2,c1,c2){
  let g=drawingContext.createLinearGradient(x1,y1,x2,y2);
  g.addColorStop(0,c1);g.addColorStop(1,c2);
  drawingContext.strokeStyle=g;line(x1,y1,x2,y2);
}

