class Yarn {
  constructor(startX, startY, length, thickness, color) {
    this.thickness = thickness * 1.5; 
    this.color = color;
    // 从颜色字符串中提取RGB值,
    this.colorObj = this.parseColor(color);
    this.particles = [];
    this.springs = [];
    this.init(startX, startY, length);
    this.fuzzySize = random(25, 40); // 大小
    this.fuzzyDensity = int(random(20, 25)); // 密度
  }

  // 添加颜色解析方法
  parseColor(colorStr) {
    // 检查是否为十六进制颜色
    if (colorStr.startsWith('#')) {
      const r = parseInt(colorStr.slice(1, 3), 16);
      const g = parseInt(colorStr.slice(3, 5), 16);
      const b = parseInt(colorStr.slice(5, 7), 16);
      return { r, g, b };
    }
    // 否则返回默认颜色
    return { r: 255, g: 255, b: 255 };
  }
  init(x, y, length) {
    let segments = 20;
    let segLen = length / segments;
    for (let i = 0; i <= segments; i++) {
      let px = x + (length * (i / segments));
      let py = y;
      let locked = (i === 0);
      let p = new Particle(px + random(-5, 5), py + random(-5, 5), locked);
      this.particles.push(p);
      if (i > 0) {
        let a = this.particles[i - 1];
        this.springs.push(new Spring(a, p, segLen, 0.8));
        if (i > 1) {
          let prev2 = this.particles[i - 2];
          this.springs.push(new Spring(prev2, p, segLen * 2, 0.2));
        }
      }
    }
  }
  applyWind() {
    for (let p of this.particles) {
      p.addForce(createVector(sin(frameCount * 0.02) * windStrength, 0.1));
    }
  }
  applyFinger(predictions) {
    const tipIndices = [4, 8, 12, 16, 20];
    const influence = 50;
    const strength = 0.3;
    predictions.forEach(hand => {
      tipIndices.forEach(i => {
        let [fx, fy] = hand.landmarks[i];
        this.particles.forEach(p => {
          let d = dist(p.pos.x, p.pos.y, fx, fy);
          if (d < influence) {
            let dir = createVector(fx - p.pos.x, fy - p.pos.y).mult(strength);
            p.pos.add(dir);
          }
        });
      });
    });
  }
  update() {
    this.particles.forEach(p => p.verlet());
    for (let i = 0; i < 5; i++) this.springs.forEach(s => s.satisfy());
    // 缓慢变化颜色
    this.hue = (this.hue + 0.2) % 360;
  }
  display() {
    // 绘制毛茸茸效果
    this.displayFuzzy();

    // 绘制主线 - 增加线条粗细以匹配更长的毛茸茸效果
    noFill();
    strokeWeight(this.thickness);
    stroke(this.color);
    beginShape();
    this.particles.forEach(p => vertex(p.pos.x, p.pos.y));
    endShape();
  }

  displayFuzzy() {
    // 为毛线之间的每个段添加毛茸茸效果
    for (let i = 0; i < this.particles.length - 1; i++) {
      let p = this.particles[i];
      let q = this.particles[i + 1];

      // 计算两点之间的距离
      let d = p5.Vector.dist(p.pos, q.pos);
      let steps = constrain(int(d / 8), 2, 10); // 增加中间点数量，使效果更密集

      // 在两点之间绘制毛茸茸效果
      for (let j = 0; j <= steps; j++) {
        let t = j / steps;
        // 正确插值x和y坐标
        let fuzzyPoint = createVector(
          lerp(p.pos.x, q.pos.x, t),
          lerp(p.pos.y, q.pos.y, t)
        );

        // 添加一些随机偏移使效果更自然
        fuzzyPoint.x += random(-2, 2);
        fuzzyPoint.y += random(-2, 2);

        // 修改大小因子，让毛茸茸效果随距离和粒子特性变化
        let sizeFactor = p.fuzzyEffect * map(sin(frameCount * 0.05 + i * 0.5), -1, 1, 0.9, 1.3);


        const { r, g, b } = this.colorObj;


        const color1 = `rgba(${r}, ${g}, ${b}, 0.8)`;  // 起点颜色 - 较不透明
        const color2 = `rgba(${r}, ${g}, ${b}, 0.2)`;  // 终点颜色 - 更透明

        drawRadiatingLines(
          fuzzyPoint, 
          this.fuzzyDensity, 
          1.2, 
          this.fuzzySize * sizeFactor, 
          color1,
          color2
        );
      }
    }
  }
}

// ----- WovenGrid: replicates original weaving pattern -----
class WovenGrid {
  constructor() {
    this.yarns = [];
    this.colors = yarnColors;
    // horizontal lines
    for (let y = 100; y <= 450; y += 60) {
      this.yarns.push(new Yarn(50, y, 500, random(8, 12), random(this.colors)));
    }
    // vertical rotated
    for (let x = 100; x <= 450; x += 60) {
      let yarn = new Yarn(x, 50, 500, random(8, 12), random(this.colors));
      yarn.particles.forEach(p => {
        let dx = p.pos.x - x;
        let dy = p.pos.y - 50;
        p.pos.set(x + dy, 50 + dx);
        p.prevPos.set(p.pos);
      });
      this.yarns.push(yarn);
    }
    // diagonal decorative (减少数量以优化性能)
    for (let i = 0; i < 4; i++) {
      let sx = random(50, 450);
      let sy = random(50, 450);
      let ang = random(TWO_PI);
      let len = random(200, 300);
      let ex = sx + cos(ang) * len;
      let ey = sy + sin(ang) * len;
      let yarn = new Yarn(sx, sy, len, random(6, 10), random(this.colors));
      yarn.particles.forEach((p, idx) => {
        let t = idx / (yarn.particles.length - 1);
        p.pos.set(lerp(sx, ex, t) + random(-10, 10), lerp(sy, ey, t) + random(-10, 10));
        p.prevPos.set(p.pos);
      });
      this.yarns.push(yarn);
    }
  }
  applyWind() { this.yarns.forEach(y => y.applyWind()); }
  applyFingerInteraction(predictions) { this.yarns.forEach(y => y.applyFinger(predictions)); }
  update() { this.yarns.forEach(y => y.update()); }
  display() { this.yarns.forEach(y => y.display()); }
}

// 绘制放射状线条 - 毛茸茸效果的核心
function drawRadiatingLines(point, density, width, size, color1, color2) {
  let baseRadius = size;
  strokeWeight(width);
  for (let i = 0; i < density; i++) {
    // 增加最小长度，使毛茸茸效果更加明显
    let radius = baseRadius * (0.7 + 0.3 * Math.random());
    let angle = Math.random() * TWO_PI;
    let endX = point.x + radius * cos(angle);
    let endY = point.y + radius * sin(angle);
    gradientLine(point.x, point.y, endX, endY, color1, color2);

    // 为每条主线添加一些较短的分支，增加蓬松感
    if (random() > 0.7) {
      let branchPoint = createVector(
        lerp(point.x, endX, random(0.3, 0.7)),
        lerp(point.y, endY, random(0.3, 0.7))
      );
      let branchAngle = angle + random(-PI/4, PI/4);
      let branchLength = radius * random(0.3, 0.5);
      let branchEndX = branchPoint.x + branchLength * cos(branchAngle);
      let branchEndY = branchPoint.y + branchLength * sin(branchAngle);
      gradientLine(branchPoint.x, branchPoint.y, branchEndX, branchEndY, color1, color2);
    }
  }
}

function gradientLine(x1, y1, x2, y2, color1, color2) {
  let grad = drawingContext.createLinearGradient(x1, y1, x2, y2);
  grad.addColorStop(0, color1);
  grad.addColorStop(1, color2);
  drawingContext.strokeStyle = grad;
  line(x1, y1, x2, y2);
}


