    bezier(p, p, 0,
      10, 10, 10 + p * 10,
      p + p * 10, p * 10, p * 10,
      0, p, p);
    pop();
    pop();
  }

  let cubeSize = mySize / (a + a / b) / 8.0;
  let plus = cubeSize / 1;

  for (let i = -cubeSize / b; i < cubeSize / b + plus; i += plus * a) {
    for (let j = -cubeSize / b; j < cubeSize / b + plus; j += plus * a) {
      for (let k = -cubeSize / b; k < cubeSize / b + plus; k += plus * a) {
        strokeCap(PROJECT);
        n = noise(i * rez + t, j * rez + t, k * rez + t) * random(0.1, 10);

        push();
        translate(i * n, j * n, k * n);
        let pNum = 50;
        for (let p = 0; p < pNum; p++) {
          translate(p * 0.5, p * 0.5, p * 0.5);
          translate(i * n, j * n, k * n);
          translate(i * sin(n), j * tan(n), k * cos(n));
          rotateX(360 / pNum * p);
          rotateY(360 / pNum * p);
          rotateZ(360 / pNum * p);
          noFill();
          stroke(random(palette));
          strokeWeight(10 * random(1, 2));
          let llSize = mySize / random(10, 100);
          box(llSize / random(10, 100));
        }

        rotateX(TAU / (b * b) * random([-a, a, b, -b]) * random([a, b, a + b, b * b]));
        rotateY(TAU / (b * b) * random([-a, a, b, -b]) * random([a, b, a + b, b * b]));
        rotateZ(TAU / (b * b) * random([-a, a, b, -b]) * random([a, b, a + b, b * b]));

        switch (random([1, 2, 3])) {
          case 1: rotateX(1 * random([-1, 1]) * frameCount / 500); break;
          case 2: rotateY(1 * random([-1, 1]) * frameCount / 100); break;
          case 3: rotateZ(n * random([-1, 1]) * frameCount / 100); break;
        }

        let planeSize = mySize / random([16, 32, 64]);
        push();
        translate(i, j, k);

        switch (random([1, 2])) {
          case 1:
            noStroke();
            fill(random(palette));
            break;
          case 2:
            noFill();
            stroke(random(palette));
            strokeWeight(random(100, 120));
            switch (random([1, 2, 3, 4])) {
              case 1: line(-planeSize / 2, -planeSize / 2, planeSize / 2, -planeSize / 2); break;
              case 2: line(planeSize / 2, -planeSize / 2, planeSize / 2, planeSize / 2); break;
              case 3: line(planeSize / 2, planeSize / 2, -planeSize / 2, planeSize / 2); break;
              case 4: line(-planeSize / 2, planeSize / 2, -planeSize / 2, -planeSize / 2); break;
            }
            break;
        }

        box(random(mySize / 500, mySize / 200) * 1.5);
        pop();

        let px = plus / random(a, int(TAU)) / b / sin(n);
        let py = plus / random(a, int(TAU)) / b / cos(n);
        let pz = plus / random(a, int(TAU)) / b / tan(n);
        push();
        noStroke();
        fill(random(palette));
        translate(px, py, pz);
        sphere(mySize / 100);
        pop();

        noFill();
        stroke(random(palette));
        strokeWeight(random(a, b) * 1 / 5 / random(1, 0.1));
        line(0, 0, 0, px, py, pz);
        noStroke();
        fill(random(palette));
        sphere(planeSize / random(5, 10));

        pop();
      }
    }
  }
  pop();
  t += 0.1 / random(100, 10);
}

